status'\" key=\"status\" class=\"meowdb-tab-panel\">\n          <div v-if=\"hasStatusData\" class=\"meowdb-card-grid\">\n            <article class=\"meowdb-card\">\n              <h4 class=\"meowdb-status-title\"><strong>当前时间</strong></h4>\n              <p>{{ entry?.time || '未设置' }}</p>\n            </article>\n            <article class=\"meowdb-card\">\n              <h4 class=\"meowdb-status-title\"><strong>当前地点</strong></h4>\n              <p>{{ sceneText }}</p>\n            </article>\n            <article class=\"meowdb-card\">\n              <h4 class=\"meowdb-status-title\"><strong>剧情摘要</strong></h4>\n              <p>{{ entry?.plot || '暂无摘要' }}</p>\n            </article>\n            <article class=\"meowdb-card\">\n              <h4 class=\"meowdb-status-title\"><strong>NSFW 进度</strong></h4>\n              <p>{{ nsfwText }}</p>\n            </article>\n          </div>\n          <div v-else class=\"meowdb-empty-state\">\n            <div class=\"meowdb-empty-illu\" aria-hidden=\"true\">\n              <span class=\"meowdb-empty-dot is-a\"></span>\n              <span class=\"meowdb-empty-dot is-b\"></span>\n              <span class=\"meowdb-empty-dot is-c\"></span>\n            </div>\n            <h4>暂无可视化数据</h4>\n            <p>发送几轮消息后，点击 AI 更新即可生成当前快照。</p>\n          </div>\n          <div class=\"meowdb-watermark\">MeowDB Story Snapshot</div>\n        </div>\n\n        <div v-else-if=\"activeTab === 'relations'\" key=\"relations\" class=\"meowdb-tab-panel meowdb-rel-wrap\">\n          <section\n            v-if=\"relations.length > 0\"\n            :class=\"['meowdb-rel-cards', relationGridClass, { 'is-scroll-x': relations.length > 8 }]\"\n          >\n            <article\n              v-for=\"relation in relations\"\n              :key=\"relation.name\"\n              class=\"meowdb-rel-card\"\n              @click=\"openRelationDetail(relation)\"\n            >\n              <header class=\"meowdb-rel-card-head\">\n                <div class=\"meowdb-rel-name\">{{ relation.name }}</div>\n                <div class=\"meowdb-rel-head-right\">\n                  <span class=\"meowdb-rel-sticker\" :class=\"getStickerClass(relation)\">{{\n                    getStickerText(relation)\n                  }}</span>\n                  <div class=\"meowdb-rel-gender\">{{ relation.gender || '未知' }}</div>\n                  <span class=\"meowdb-rel-peek\">查看详情</span>\n                </div>\n              </header>\n              <div class=\"meowdb-rel-line\">⌾ {{ relation.genitalStatus || '未记录' }}</div>\n              <div class=\"meowdb-rel-line\">\n                🏷️ {{ relation.identity || '身份未知' }} · {{ relation.personality || '人格未知' }}\n              </div>\n              <div class=\"meowdb-rel-line\">\n                📍 {{ relation.coordinate || '位置未知' }} · ⚡ {{ relation.action || '动作未知' }}\n              </div>\n              <div class=\"meowdb-rel-line\">👗 {{ relation.clothing || summarizeClothing(relation) }}</div>\n              <div class=\"meowdb-rel-line\">👤 {{ relation.appearance || summarizeAppearance(relation) }}</div>\n              <footer class=\"meowdb-rel-card-foot\">\n                <span>{{ relation.bond || '羁绊未定义' }}</span>\n                <strong class=\"meowdb-favor-block\">\n                  <span>{{ formatOne(getFavorBase(relation)) }}</span>\n                  <span :class=\"deltaClass(getFavorDelta(relation))\">{{ formatSigned(getFavorDelta(relation)) }}</span>\n                  <span>= {{ formatOne(getFavor(relation)) }}</span>\n                </strong>\n              </footer>\n            </article>\n          </section>\n          <div v-else class=\"meowdb-empty-state meowdb-empty-state-rel\">\n            <div class=\"meowdb-empty-illu\" aria-hidden=\"true\">\n              <span class=\"meowdb-empty-dot is-a\"></span>\n              <span class=\"meowdb-empty-dot is-b\"></span>\n              <span class=\"meowdb-empty-dot is-c\"></span>\n            </div>\n            <h4>暂无关系数据</h4>\n            <p>请先执行 AI 更新，或在 relations_json 中写入角色关系。</p>\n          </div>\n\n          <details v-if=\"relations.length > 0\" class=\"meowdb-rel-graph-collapse\">\n            <summary>\n              <i class=\"fa-solid fa-circle-nodes\"></i>\n              关系图谱（点击展开）\n            </summary>\n            <div class=\"meowdb-rel-graph-shell\">\n              <svg class=\"meowdb-rel-graph\" viewBox=\"0 0 760 360\" role=\"img\" aria-label=\"关系图谱\">\n                <g v-for=\"edge in graphEdges\" :key=\"edge.id\" class=\"meowdb-rel-graph-edge\">\n                  <line :x1=\"edge.from.x\" :y1=\"edge.from.y\" :x2=\"edge.to.x\" :y2=\"edge.to.y\" />\n                  <text :x=\"edge.labelX\" :y=\"edge.labelY\">{{ edge.label }}</text>\n                </g>\n                <g\n                  v-for=\"node in graphNodes\"\n                  :key=\"node.name\"\n                  class=\"meowdb-rel-graph-node\"\n                  @click=\"openRelationByName(node.name)\"\n                >\n                  <circle :cx=\"node.x\" :cy=\"node.y\" :r=\"node.isCore ? 11 : 8\" :fill=\"node.color\" />\n                  <text :x=\"node.x\" :y=\"node.y + (node.isCore ? 24 : 21)\">{{ node.name }}</text>\n                </g>\n              </svg>\n            </div>\n          </details>\n        </div>\n\n        <div v-else key=\"settings\" class=\"meowdb-tab-panel\">\n          <div class=\"meowdb-palette-card\">\n            <div class=\"meowdb-palette-head\">\n              <b>关系图配色组（1组5色）</b>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"resetPalette\">恢复默认</button>\n            </div>\n            <div class=\"meowdb-palette-grid\">\n              <label v-for=\"(_, index) in paletteValues\" :key=\"index\" class=\"meowdb-palette-cell\">\n                <span>颜色 {{ index + 1 }}</span>\n                <input type=\"color\" v-model=\"paletteValues[index]\" @change=\"applyPaletteColor(index)\" />\n              </label>\n            </div>\n          </div>\n        </div>\n      </Transition>\n\n      <Transition name=\"meowdb-slide\">\n        <aside v-if=\"selectedRelation\" class=\"meowdb-rel-detail-mask\" @click.self=\"selectedRelation = null\">\n          <article\n            class=\"meowdb-rel-detail\"\n            @keydown.left.prevent=\"selectPrev\"\n            @keydown.right.prevent=\"selectNext\"\n            tabindex=\"0\"\n          >\n            <button class=\"meowdb-rel-detail-close\" type=\"button\" @click=\"selectedRelation = null\">\n              <i class=\"fa-solid fa-xmark\"></i>\n            </button>\n            <h3>{{ selectedRelation.name }}</h3>\n\n            <div class=\"meowdb-rel-detail-nav\">\n              <button class=\"menu_button\" type=\"button\" :disabled=\"selectedIndex <= 0\" @click=\"selectPrev\">\n                上一位\n              </button>\n              <span>{{ selectedIndex + 1 }} / {{ relations.length }}</span>\n              <button\n                class=\"menu_button\"\n                type=\"button\"\n                :disabled=\"selectedIndex >= relations.length - 1\"\n                @click=\"selectNext\"\n              >\n                下一位\n              </button>\n            </div>\n\n            <div class=\"meowdb-rel-bulk-actions\">\n              <button\n                class=\"menu_button\"\n                type=\"button\"\n                :disabled=\"pendingChanges.length === 0\"\n                @click=\"savePendingChanges\"\n              >\n                保存修改（{{ pendingChanges.length }}）\n              </button>\n              <button\n                class=\"menu_button\"\n                type=\"button\"\n                :disabled=\"manualFields.length === 0\"\n                @click=\"restoreAllManualFields\"\n              >\n                还原手动字段（{{ manualFields.length }}）\n              </button>\n            </div>\n\n            <section class=\"meowdb-rel-edit-section\">\n              <h4 class=\"meowdb-rel-section-title\"><i class=\"fa-solid fa-id-card\"></i><span>基础信息</span></h4>\n              <div class=\"meowdb-rel-edit-grid meowdb-bento-grid meowdb-bento-core\">\n                <div\n                  v-for=\"field in coreFields\"\n                  :key=\"field.key\"\n                  class=\"meowdb-edit-cell\"\n                  :class=\"[\n                    'meowdb-bento-cell',\n                    getFieldClass('core', field.key),\n                    { 'is-manual': isFieldManual(field.key), 'is-pending': isFieldPending(field.key) },\n                  ]\"\n                >\n                  <label>{{ field.label }}</label>\n                  <input class=\"meowdb-input\" :type=\"field.type || 'text'\" v-model=\"draft[field.key]\" />\n                </div>\n              </div>\n            </section>\n\n            <section class=\"meowdb-rel-edit-section\">\n              <h4 class=\"meowdb-rel-section-title\"><i class=\"fa-solid fa-shirt\"></i><span>服饰拆解</span></h4>\n              <div class=\"meowdb-rel-edit-grid meowdb-bento-grid meowdb-bento-clothing\">\n                <div\n                  v-for=\"field in clothingFields\"\n                  :key=\"field.key\"\n                  class=\"meowdb-edit-cell\"\n                  :class=\"[\n                    'meowdb-bento-cell',\n                    getFieldClass('clothing', field.key),\n                    { 'is-manual': isFieldManual(field.key), 'is-pending': isFieldPending(field.key) },\n                  ]\"\n                >\n                  <label>{{ field.label }}</label>\n                  <input class=\"meowdb-input\" v-model=\"draft[field.key]\" />\n                </div>\n              </div>\n            </section>\n\n            <section class=\"meowdb-rel-edit-section\">\n              <h4 class=\"meowdb-rel-section-title\"><i class=\"fa-solid fa-user\"></i><span>外貌拆解</span></h4>\n              <div class=\"meowdb-rel-edit-grid meowdb-bento-grid meowdb-bento-appearance\">\n                <div\n                  v-for=\"field in appearanceFields\"\n                  :key=\"field.key\"\n                  class=\"meowdb-edit-cell\"\n                  :class=\"[\n                    'meowdb-bento-cell',\n                    getFieldClass('appearance', field.key),\n                    { 'is-manual': isFieldManual(field.key), 'is-pending': isFieldPending(field.key) },\n                  ]\"\n                >\n                  <label>{{ field.label }}</label>\n                  <input class=\"meowdb-input\" v-model=\"draft[field.key]\" />\n                </div>\n              </div>\n            </section>\n          </article>\n        </aside>\n      </Transition>\n    </template>\n  </section>\n</template>\n\n<script setup lang=\"ts\">\nimport { runManualAiUpdate } from '@/modules/ai-updater';\nimport { getCurrentEntry, saveCurrentEntry } from '@/modules/data-manager';\nimport { useSettingsStore } from '@/store/settings';\nimport type { CharacterRelation } from '@/type/meowdb';\nimport { storeToRefs } from 'pinia';\n\ntype VisualTab = 'status' | 'relations' | 'settings';\n\ninterface EditableField {\n  key: string;\n  label: string;\n  type?: 'text' | 'number';\n}\n\nconst defaultPalette = ['#7dd3fc', '#f9a8d4', '#86efac', '#fcd34d', '#c4b5fd'];\n\nconst coreFields: EditableField[] = [\n  { key: 'gender', label: '性别' },\n  { key: 'birthday', label: '生日' },\n  { key: 'genitalStatus', label: '性器官及状态' },\n  { key: 'identity', label: '身份' },\n  { key: 'personality', label: '核心人格' },\n  { key: 'sexExp', label: '性经验' },\n  { key: 'coordinate', label: '当前位置' },\n  { key: 'action', label: '实时动作' },\n  { key: 'bond', label: '当前羁绊' },\n  { key: 'favorBase', label: '好感基础值', type: 'number' },\n  { key: 'favorDelta', label: '好感增减值', type: 'number' },\n  { key: 'favorChange', label: '增减原因' },\n  { key: 'clothing', label: '服饰总览' },\n  { key: 'appearance', label: '外貌总览' },\n];\n\nconst clothingFields: EditableField[] = [\n  { key: 'clothingParts.headwear', label: '头饰' },\n  { key: 'clothingParts.jewelry', label: '首饰' },\n  { key: 'clothingParts.facewear', label: '面饰' },\n  { key: 'clothingParts.upper', label: '上装' },\n  { key: 'clothingParts.lower', label: '下装' },\n  { key: 'clothingParts.underwearTop', label: '内衣' },\n  { key: 'clothingParts.underwearBottom', label: '内裤' },\n  { key: 'clothingParts.shoesSocks', label: '鞋袜' },\n];\n\nconst appearanceFields: EditableField[] = [\n  { key: 'appearanceParts.hairColor', label: '发色' },\n  { key: 'appearanceParts.eyeColor', label: '瞳色' },\n  { key: 'appearanceParts.height', label: '身高' },\n  { key: 'appearanceParts.bodyType', label: '体型' },\n];\n\nconst { settings } = storeToRefs(useSettingsStore());\nconst entry = ref(getCurrentEntry());\nconst updating = ref(false);\nconst selectedRelation = ref<CharacterRelation | null>(null);\nconst draft = reactive<Record<string, string>>({});\n\nconst activeTab = ref<VisualTab>(normalizeTab(settings.value.visual_active_tab));\nconst panelCollapsed = ref(Boolean(settings.value.visual_panel_collapsed));\nconst paletteValues = ref<string[]>([...defaultPalette]);\n\nconst relations = computed(() => entry.value?.relations ?? []);\n\nconst relationGridClass = computed(() => {\n  const count = relations.value.length;\n  if (count <= 1) return 'cols-1';\n  if (count <= 4) return 'cols-2';\n  if (count <= 6) return 'cols-3';\n  return 'cols-4';\n});\n\nconst selectedIndex = computed(() => {\n  if (!selectedRelation.value) return -1;\n  return relations.value.findIndex(item => item.name === selectedRelation.value?.name);\n});\n\nconst coreRelation = computed(() => {\n  const list = relations.value;\n  if (!list.length) return null;\n  return list.find(item => /<user>|\\buser\\b/i.test(item.name || '')) ?? list[0];\n});\n\nconst graphNodes = computed(() => {\n  const list = relations.value;\n  if (!list.length) return [] as Array<{ name: string; x: number; y: number; isCore: boolean; color: string }>;\n\n  const core = coreRelation.value ?? list[0];\n  const others = list.filter(item => item.name !== core.name);\n  const center = { x: 380, y: 170 };\n\n  const nodes = [{ name: core.name, x: center.x, y: center.y, isCore: true, color: '#7ee7cf' }];\n  const radiusX = 260;\n  const radiusY = 130;\n\n  others.forEach((item, index) => {\n    const angle = (Math.PI * 2 * index) / Math.max(others.length, 1) - Math.PI / 2;\n    nodes.push({\n      name: item.name,\n      x: center.x + Math.cos(angle) * radiusX,\n      y: center.y + Math.sin(angle) * radiusY,\n      isCore: false,\n      color: pickColor(item.name),\n    });\n  });\n\n  return nodes;\n});\n\nconst graphEdges = computed(() => {\n  const nodes = graphNodes.value;\n  const coreNode = nodes.find(node => node.isCore);\n  if (!coreNode) {\n    return [] as Array<{\n      id: string;\n      from: { x: number; y: number };\n      to: { x: number; y: number };\n      label: string;\n      labelX: number;\n      labelY: number;\n    }>;\n  }\n\n  return nodes\n    .filter(node => !node.isCore)\n    .map(node => {\n      const relation = relations.value.find(item => item.name === node.name);\n      const label = relation?.bond || '关联';\n      return {\n        id: `${coreNode.name}->${node.name}`,\n        from: { x: coreNode.x, y: coreNode.y },\n        to: { x: node.x, y: node.y },\n        label,\n        labelX: (coreNode.x + node.x) / 2,\n        labelY: (coreNode.y + node.y) / 2,\n      };\n    });\n});\n\nconst sceneText = computed(() => {\n  const scene = entry.value?.scene;\n  if (!scene) return '未设置';\n  return `${scene.main} - ${scene.sub}（停留回合：${scene.stayRounds}）`;\n});\n\nconst nsfwText = computed(() => {\n  const nsfw = entry.value?.nsfw;\n  if (!nsfw) return '0/0';\n  return `${nsfw.current}/${nsfw.max}`;\n});\n\nconst hasStatusData = computed(() => {\n  const e = entry.value;\n  if (!e) return false;\n  return Boolean(e.time || e.plot || e.scene?.main || e.scene?.sub || e.nsfw);\n});\n\nconst allFields = computed(() => [...coreFields, ...clothingFields, ...appearanceFields]);\n\nconst pendingChanges = computed(() => {\n  if (!selectedRelation.value) return [] as string[];\n\n  return allFields.value\n    .filter(field => {\n      const oldValue = getByPath(selectedRelation.value as Record<string, any>, field.key);\n      const draftValue = coerceByType(draft[field.key], field.type);\n      return !Object.is(oldValue, draftValue);\n    })\n    .map(field => field.key);\n});\n\nconst manualFields = computed(() => {\n  if (!selectedRelation.value) return [] as string[];\n  return Object.keys(selectedRelation.value.manualEdited ?? {}).filter(\n    key => selectedRelation.value?.manualEdited?.[key],\n  );\n});\n\nwatch(activeTab, tab => {\n  settings.value.visual_active_tab = tab;\n});\n\nwatch(panelCollapsed, collapsed => {\n  settings.value.visual_panel_collapsed = collapsed;\n});\n\nwatch(\n  () => settings.value.relation_colors,\n  next => {\n    const list = Array.isArray(next) ? next.slice(0, 5) : [];\n    while (list.length < 5) list.push(defaultPalette[list.length]);\n    paletteValues.value = list;\n  },\n  { immediate: true, deep: true },\n);\n\nwatch(\n  selectedRelation,\n  relation => {\n    Object.keys(draft).forEach(key => delete draft[key]);\n    if (!relation) return;\n\n    allFields.value.forEach(field => {\n      draft[field.key] = String(getByPath(relation as Record<string, any>, field.key) ?? '');\n    });\n  },\n  { immediate: true },\n);\n\nfunction normalizeTab(tab: string | undefined): VisualTab {\n  if (tab === 'relations' || tab === 'settings' || tab === 'status') return tab;\n  return 'status';\n}\n\nfunction toggleCollapse() {\n  panelCollapsed.value = !panelCollapsed.value;\n}\n\nfunction pickColor(name: string): string {\n  const palette = normalizePalette(settings.value.relation_colors);\n  let hash = 0;\n  for (let i = 0; i < name.length; i += 1) {\n    hash = (hash << 5) - hash + name.charCodeAt(i);\n    hash |= 0;\n  }\n  return palette[Math.abs(hash) % palette.length];\n}\n\nfunction normalizePalette(colors: string[] | undefined): string[] {\n  if (!Array.isArray(colors) || colors.length < 5) return defaultPalette;\n  return colors\n    .slice(0, 5)\n    .map((color, idx) => (typeof color === 'string' && color.trim() ? color : defaultPalette[idx]));\n}\n\nfunction applyPaletteColor(index: number) {\n  const next = [...paletteValues.value];\n  while (next.length < 5) next.push(defaultPalette[next.length]);\n  settings.value.relation_colors = next.slice(0, 5);\n}\n\nfunction resetPalette() {\n  paletteValues.value = [...defaultPalette];\n  settings.value.relation_colors = [...defaultPalette];\n}\n\nfunction formatOne(value: number | undefined) {\n  if (typeof value !== 'number' || Number.isNaN(value)) return '0.0';\n  return value.toFixed(1);\n}\n\nfunction formatSigned(value: number | undefined) {\n  if (typeof value !== 'number' || Number.isNaN(value)) return '+0.0';\n  return value >= 0 ? `+${value.toFixed(1)}` : value.toFixed(1);\n}\n\nfunction deltaClass(value: number | undefined) {\n  if (typeof value !== 'number' || Number.isNaN(value) || value === 0) return 'is-flat';\n  return value > 0 ? 'is-up' : 'is-down';\n}\n\nfunction getFavor(relation: CharacterRelation) {\n  return typeof relation.favor === 'number' ? relation.favor : getFavorBase(relation) + getFavorDelta(relation);\n}\n\nfunction getFavorBase(relation: CharacterRelation) {\n  if (typeof relation.favorBase === 'number') return relation.favorBase;\n  if (typeof relation.favor === 'number' && typeof relation.favorDelta === 'number')\n    return relation.favor - relation.favorDelta;\n  return typeof relation.favor === 'number' ? relation.favor : 0;\n}\n\nfunction getFavorDelta(relation: CharacterRelation) {\n  return typeof relation.favorDelta === 'number' ? relation.favorDelta : 0;\n}\n\nfunction summarizeClothing(relation: CharacterRelation) {\n  const parts = relation.clothingParts;\n  if (!parts) return '服饰未记录';\n  return [parts.upper, parts.lower, parts.shoesSocks].filter(Boolean).join(' / ') || '服饰未记录';\n}\n\nfunction summarizeAppearance(relation: CharacterRelation) {\n  const parts = relation.appearanceParts;\n  if (!parts) return '外貌未记录';\n  return [parts.hairColor, parts.eyeColor, parts.height, parts.bodyType].filter(Boolean).join(' / ') || '外貌未记录';\n}\n\nfunction hasManualEdited(relation: CharacterRelation) {\n  return Object.values(relation.manualEdited ?? {}).some(Boolean);\n}\n\nfunction getStickerText(relation: CharacterRelation) {\n  if (hasManualEdited(relation)) return '手动锁定';\n  const delta = getFavorDelta(relation);\n  if (delta >= 0.2) return '升温';\n  if (delta <= -0.2) return '紧张';\n\n  const hint = `${relation.action ?? ''} ${relation.bond ?? ''} ${relation.personality ?? ''}`;\n  if (/观察|试探|打量|克制|防备|谨慎|沉默/.test(hint)) return '观察中';\n  return '观察中';\n}\n\nfunction getStickerClass(relation: CharacterRelation) {\n  const text = getStickerText(relation);\n  if (text === '手动锁定') return 'is-manual';\n  if (text === '升温') return 'is-up';\n  if (text === '紧张') return 'is-down';\n  return 'is-watch';\n}\n\nfunction refresh() {\n  entry.value = getCurrentEntry();\n}\n\nfunction openRelationDetail(relation: CharacterRelation) {\n  selectedRelation.value = relation;\n}\n\nfunction openRelationByName(name: string) {\n  const relation = relations.value.find(item => item.name === name);\n  if (relation) openRelationDetail(relation);\n}\n\nfunction selectPrev() {\n  if (selectedIndex.value <= 0) return;\n  selectedRelation.value = relations.value[selectedIndex.value - 1] ?? null;\n}\n\nfunction selectNext() {\n  if (selectedIndex.value < 0 || selectedIndex.value >= relations.value.length - 1) return;\n  selectedRelation.value = relations.value[selectedIndex.value + 1] ?? null;\n}\n\nfunction getFieldClass(section: 'core' | 'clothing' | 'appearance', key: string) {\n  if (section == 'core') {\n    if (key == 'bond' || key == 'favorChange' || key == 'clothing' || key == 'appearance') return 'is-wide';\n    if (key == 'action' || key == 'coordinate') return 'is-mid';\n    return 'is-compact';\n  }\n\n  if (section == 'clothing') {\n    if (key.endsWith('upper') || key.endsWith('lower') || key.endsWith('shoesSocks')) return 'is-mid';\n    return 'is-compact';\n  }\n\n  if (section == 'appearance') {\n    if (key.endsWith('height') || key.endsWith('bodyType')) return 'is-mid';\n    return 'is-compact';\n  }\n\n  return 'is-compact';\n}\n\nfunction isFieldManual(path: string) {\n  return Boolean(selectedRelation.value?.manualEdited?.[path]);\n}\n\nfunction isFieldPending(path: string) {\n  return pendingChanges.value.includes(path);\n}\n\nfunction coerceByType(value: string, type: EditableField['type']) {\n  if (type !== 'number') return value ?? '';\n  const n = Number(value);\n  return Number.isFinite(n) ? n : 0;\n}\n\nasync function savePendingChanges() {\n  if (!entry.value || !selectedRelation.value) return;\n  const index = selectedIndex.value;\n  if (index < 0) return;\n\n  const relation = entry.value.relations[index];\n  for (const key of pendingChanges.value) {\n    const field = allFields.value.find(item => item.key === key);\n    const oldValue = getByPath(relation as Record<string, any>, key);\n    const newValue = coerceByType(draft[key], field?.type);\n\n    if (relation.aiBaseline[key] === undefined && (typeof oldValue === 'string' || typeof oldValue === 'number')) {\n      relation.aiBaseline[key] = oldValue;\n    }\n\n    setByPath(relation as Record<string, any>, key, newValue);\n    relation.manualEdited[key] = true;\n  }\n\n  normalizeFavorFields(relation);\n  await persistEntry(relation.name);\n}\n\nasync function restoreAllManualFields() {\n  if (!entry.value || !selectedRelation.value) return;\n  const index = selectedIndex.value;\n  if (index < 0) return;\n\n  const relation = entry.value.relations[index];\n  for (const key of Object.keys(relation.manualEdited ?? {})) {\n    if (!relation.manualEdited[key]) continue;\n    const baseline = relation.aiBaseline?.[key];\n    if (baseline !== undefined) {\n      setByPath(relation as Record<string, any>, key, baseline);\n      draft[key] = String(baseline);\n    }\n    delete relation.manualEdited[key];\n    delete relation.aiBaseline[key];\n  }\n\n  normalizeFavorFields(relation);\n  await persistEntry(relation.name);\n}\n\nfunction normalizeFavorFields(relation: CharacterRelation) {\n  const base = Number(relation.favorBase ?? 0);\n  const delta = Number(relation.favorDelta ?? 0);\n  relation.favorBase = Number.isFinite(base) ? Number(base.toFixed(1)) : 0;\n  relation.favorDelta = Number.isFinite(delta) ? Number(delta.toFixed(1)) : 0;\n  relation.favor = Number((relation.favorBase + relation.favorDelta).toFixed(1));\n}\n\nfunction getByPath(target: Record<string, any>, path: string) {\n  return path.split('.').reduce<any>((acc, key) => (acc == null ? undefined : acc[key]), target);\n}\n\nfunction setByPath(target: Record<string, any>, path: string, value: unknown) {\n  const keys = path.split('.');\n  const last = keys.pop();\n  if (!last) return;\n\n  let cursor: Record<string, any> = target;\n  for (const key of keys) {\n    if (cursor[key] == null || typeof cursor[key] !== 'object') cursor[key] = {};\n    cursor = cursor[key];\n  }\n  cursor[last] = value;\n}\n\nasync function persistEntry(activeName?: string) {\n  if (!entry.value) return;\n  const ok = await saveCurrentEntry(entry.value);\n  if (!ok) {\n    toastr.error('保存失败，字段值不合法');\n    return;\n  }\n\n  refresh();\n  if (activeName) {\n    selectedRelation.value = relations.value.find(item => item.name === activeName) ?? null;\n  }\n}\n\nasync function manualUpdate() {\n  if (updating.value) return;\n  updating.value = true;\n\n  const result = await runManualAiUpdate();\n  updating.value = false;\n\n  if (!result.ok) {\n    toastr.error(result.error || 'AI 更新失败');\n    return;\n  }\n\n  refresh();\n  toastr.success('AI 更新完成');\n}\n\nfunction onDataUpdated() {\n  refresh();\n}\n\nonMounted(() => {\n  window.addEventListener('meowdb:data-updated', onDataUpdated);\n});\n\nonBeforeUnmount(() => {\n  window.removeEventListener('meowdb:data-updated', onDataUpdated);\n});\n</script>\n","<template>\n  <section class=\"meowdb-visual-shell\" :class=\"{ 'is-collapsed': panelCollapsed }\">\n    <header class=\"meowdb-visual-header\">\n      <div\n        class=\"meowdb-title-group meowdb-title-toggle\"\n        role=\"button\"\n        tabindex=\"0\"\n        @click=\"toggleCollapse\"\n        @keydown.enter.prevent=\"toggleCollapse\"\n        @keydown.space.prevent=\"toggleCollapse\"\n      >\n        <i class=\"fa-solid fa-paw meowdb-brand-icon\" aria-hidden=\"true\"></i>\r\n        <h3>MeowDB 喵喵表格</h3>\n        <span class=\"meowdb-serial-badge\">{{ entry?.serial || '未编号' }}</span>\n      </div>\n      <div class=\"meowdb-header-actions\">\n        <button class=\"menu_button meowdb-action-btn\" :disabled=\"updating\" @click=\"refresh\">\n          <i class=\"fa-solid fa-rotate\"></i>\n          <span>刷新</span>\n        </button>\n        <button class=\"menu_button meowdb-action-btn meowdb-action-btn-ai\" :disabled=\"updating\" @click=\"manualUpdate\">\n          <i class=\"fa-solid fa-wand-magic-sparkles\"></i>\n          <span>{{ updating ? '更新中...' : 'AI更新' }}</span>\n        </button>\n      </div>\n    </header>\n\n    <template v-if=\"!panelCollapsed\">\n      <nav class=\"meowdb-tab-row\">\n        <button class=\"meowdb-tab\" :class=\"{ 'is-active': activeTab === 'status' }\" @click=\"activeTab = 'status'\">\n          状态\n        </button>\n        <button class=\"meowdb-tab\" :class=\"{ 'is-active': activeTab === 'relations' }\" @click=\"activeTab = 'relations'\">\n          关系\n        </button>\n        <button class=\"meowdb-tab\" disabled>时间线</button>\n        <button class=\"meowdb-tab\" disabled>物品</button>\n        <button class=\"meowdb-tab\" disabled>场景</button>\n        <button class=\"meowdb-tab\" :class=\"{ 'is-active': activeTab === 'settings' }\" @click=\"activeTab = 'settings'\">\n          设置\n        </button>\n      </nav>\n\n      <Transition name=\"meowdb-fade\" mode=\"out-in\">\n        <div v-if=\"activeTab === 'status'\" key=\"status\" class=\"meowdb-tab-panel\">\n          <div v-if=\"hasStatusData\" class=\"meowdb-card-grid\">\n            <article class=\"meowdb-card\">\n              <h4 class=\"meowdb-status-title\"><strong>当前时间</strong></h4>\n              <p>{{ entry?.time || '未设置' }}</p>\n            </article>\n            <article class=\"meowdb-card\">\n              <h4 class=\"meowdb-status-title\"><strong>当前地点</strong></h4>\n              <p>{{ sceneText }}</p>\n            </article>\n            <article class=\"meowdb-card\">\n              <h4 class=\"meowdb-status-title\"><strong>剧情摘要</strong></h4>\n              <p>{{ entry?.plot || '暂无摘要' }}</p>\n            </article>\n            <article class=\"meowdb-card\">\n              <h4 class=\"meowdb-status-title\"><strong>NSFW 进度</strong></h4>\n              <p>{{ nsfwText }}</p>\n            </article>\n          </div>\n          <div v-else class=\"meowdb-empty-state\">\n            <div class=\"meowdb-empty-illu\" aria-hidden=\"true\">\n              <span class=\"meowdb-empty-dot is-a\"></span>\n              <span class=\"meowdb-empty-dot is-b\"></span>\n              <span class=\"meowdb-empty-dot is-c\"></span>\n            </div>\n            <h4>暂无可视化数据</h4>\n            <p>发送几轮消息后，点击 AI 更新即可生成当前快照。</p>\n          </div>\n          <div class=\"meowdb-watermark\">MeowDB Story Snapshot</div>\n        </div>\n\n        <div v-else-if=\"activeTab === 'relations'\" key=\"relations\" class=\"meowdb-tab-panel meowdb-rel-wrap\">\n          <section\n            v-if=\"relations.length > 0\"\n            :class=\"['meowdb-rel-cards', relationGridClass, { 'is-scroll-x': relations.length > 8 }]\"\n          >\n            <article\n              v-for=\"relation in relations\"\n              :key=\"relation.name\"\n              class=\"meowdb-rel-card\"\n              @click=\"openRelationDetail(relation)\"\n            >\n              <header class=\"meowdb-rel-card-head\">\n                <div class=\"meowdb-rel-name\">{{ relation.name }}</div>\n                <div class=\"meowdb-rel-head-right\">\n                  <span class=\"meowdb-rel-sticker\" :class=\"getStickerClass(relation)\">{{\n                    getStickerText(relation)\n                  }}</span>\n                  <div class=\"meowdb-rel-gender\">{{ relation.gender || '未知' }}</div>\n                  <span class=\"meowdb-rel-peek\">查看详情</span>\n                </div>\n              </header>\n              <div class=\"meowdb-rel-line\">⌾ {{ relation.genitalStatus || '未记录' }}</div>\n              <div class=\"meowdb-rel-line\">\n                🏷️ {{ relation.identity || '身份未知' }} · {{ relation.personality || '人格未知' }}\n              </div>\n              <div class=\"meowdb-rel-line\">\n                📍 {{ relation.coordinate || '位置未知' }} · ⚡ {{ relation.action || '动作未知' }}\n              </div>\n              <div class=\"meowdb-rel-line\">👗 {{ relation.clothing || summarizeClothing(relation) }}</div>\n              <div class=\"meowdb-rel-line\">👤 {{ relation.appearance || summarizeAppearance(relation) }}</div>\n              <footer class=\"meowdb-rel-card-foot\">\n                <span>{{ relation.bond || '羁绊未定义' }}</span>\n                <strong class=\"meowdb-favor-block\">\n                  <span>{{ formatOne(getFavorBase(relation)) }}</span>\n                  <span :class=\"deltaClass(getFavorDelta(relation))\">{{ formatSigned(getFavorDelta(relation)) }}</span>\n                  <span>= {{ formatOne(getFavor(relation)) }}</span>\n                </strong>\n              </footer>\n            </article>\n          </section>\n          <div v-else class=\"meowdb-empty-state meowdb-empty-state-rel\">\n            <div class=\"meowdb-empty-illu\" aria-hidden=\"true\">\n              <span class=\"meowdb-empty-dot is-a\"></span>\n              <span class=\"meowdb-empty-dot is-b\"></span>\n              <span class=\"meowdb-empty-dot is-c\"></span>\n            </div>\n            <h4>暂无关系数据</h4>\n            <p>请先执行 AI 更新，或在 relations_json 中写入角色关系。</p>\n          </div>\n\n          <details v-if=\"relations.length > 0\" class=\"meowdb-rel-graph-collapse\">\n            <summary>\n              <i class=\"fa-solid fa-circle-nodes\"></i>\n              关系图谱（点击展开）\n            </summary>\n            <div class=\"meowdb-rel-graph-shell\">\n              <svg class=\"meowdb-rel-graph\" viewBox=\"0 0 760 360\" role=\"img\" aria-label=\"关系图谱\">\n                <g v-for=\"edge in graphEdges\" :key=\"edge.id\" class=\"meowdb-rel-graph-edge\">\n                  <line :x1=\"edge.from.x\" :y1=\"edge.from.y\" :x2=\"edge.to.x\" :y2=\"edge.to.y\" />\n                  <text :x=\"edge.labelX\" :y=\"edge.labelY\">{{ edge.label }}</text>\n                </g>\n                <g\n                  v-for=\"node in graphNodes\"\n                  :key=\"node.name\"\n                  class=\"meowdb-rel-graph-node\"\n                  @click=\"openRelationByName(node.name)\"\n                >\n                  <circle :cx=\"node.x\" :cy=\"node.y\" :r=\"node.isCore ? 11 : 8\" :fill=\"node.color\" />\n                  <text :x=\"node.x\" :y=\"node.y + (node.isCore ? 24 : 21)\">{{ node.name }}</text>\n                </g>\n              </svg>\n            </div>\n          </details>\n        </div>\n\n        <div v-else key=\"settings\" class=\"meowdb-tab-panel\">\n          <div class=\"meowdb-palette-card\">\n            <div class=\"meowdb-palette-head\">\n              <b>关系图配色组（1组5色）</b>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"resetPalette\">恢复默认</button>\n            </div>\n            <div class=\"meowdb-palette-grid\">\n              <label v-for=\"(_, index) in paletteValues\" :key=\"index\" class=\"meowdb-palette-cell\">\n                <span>颜色 {{ index + 1 }}</span>\n                <input type=\"color\" v-model=\"paletteValues[index]\" @change=\"applyPaletteColor(index)\" />\n              </label>\n            </div>\n          </div>\n        </div>\n      </Transition>\n\n      <Transition name=\"meowdb-slide\">\n        <aside v-if=\"selectedRelation\" class=\"meowdb-rel-detail-mask\" @click.self=\"selectedRelation = null\">\n          <article\n            class=\"meowdb-rel-detail\"\n            @keydown.left.prevent=\"selectPrev\"\n            @keydown.right.prevent=\"selectNext\"\n            tabindex=\"0\"\n          >\n            <button class=\"meowdb-rel-detail-close\" type=\"button\" @click=\"selectedRelation = null\">\n              <i class=\"fa-solid fa-xmark\"></i>\n            </button>\n            <h3>{{ selectedRelation.name }}</h3>\n\n            <div class=\"meowdb-rel-detail-nav\">\n              <button class=\"menu_button\" type=\"button\" :disabled=\"selectedIndex <= 0\" @click=\"selectPrev\">\n                上一位\n              </button>\n              <span>{{ selectedIndex + 1 }} / {{ relations.length }}</span>\n              <button\n                class=\"menu_button\"\n                type=\"button\"\n                :disabled=\"selectedIndex >= relations.length - 1\"\n                @click=\"selectNext\"\n              >\n                下一位\n              </button>\n            </div>\n\n            <div class=\"meowdb-rel-bulk-actions\">\n              <button\n                class=\"menu_button\"\n                type=\"button\"\n                :disabled=\"pendingChanges.length === 0\"\n                @click=\"savePendingChanges\"\n              >\n                保存修改（{{ pendingChanges.length }}）\n              </button>\n              <button\n                class=\"menu_button\"\n                type=\"button\"\n                :disabled=\"manualFields.length === 0\"\n                @click=\"restoreAllManualFields\"\n              >\n                还原手动字段（{{ manualFields.length }}）\n              </button>\n            </div>\n\n            <section class=\"meowdb-rel-edit-section\">\n              <h4 class=\"meowdb-rel-section-title\"><i class=\"fa-solid fa-id-card\"></i><span>基础信息</span></h4>\n              <div class=\"meowdb-rel-edit-grid meowdb-bento-grid meowdb-bento-core\">\n                <div\n                  v-for=\"field in coreFields\"\n                  :key=\"field.key\"\n                  class=\"meowdb-edit-cell\"\n                  :class=\"[\n                    'meowdb-bento-cell',\n                    getFieldClass('core', field.key),\n                    { 'is-manual': isFieldManual(field.key), 'is-pending': isFieldPending(field.key) },\n                  ]\"\n                >\n                  <label>{{ field.label }}</label>\n                  <input class=\"meowdb-input\" :type=\"field.type || 'text'\" v-model=\"draft[field.key]\" />\n                </div>\n              </div>\n            </section>\n\n            <section class=\"meowdb-rel-edit-section\">\n              <h4 class=\"meowdb-rel-section-title\"><i class=\"fa-solid fa-shirt\"></i><span>服饰拆解</span></h4>\n              <div class=\"meowdb-rel-edit-grid meowdb-bento-grid meowdb-bento-clothing\">\n                <div\n                  v-for=\"field in clothingFields\"\n                  :key=\"field.key\"\n                  class=\"meowdb-edit-cell\"\n                  :class=\"[\n                    'meowdb-bento-cell',\n                    getFieldClass('clothing', field.key),\n                    { 'is-manual': isFieldManual(field.key), 'is-pending': isFieldPending(field.key) },\n                  ]\"\n                >\n                  <label>{{ field.label }}</label>\n                  <input class=\"meowdb-input\" v-model=\"draft[field.key]\" />\n                </div>\n              </div>\n            </section>\n\n            <section class=\"meowdb-rel-edit-section\">\n              <h4 class=\"meowdb-rel-section-title\"><i class=\"fa-solid fa-user\"></i><span>外貌拆解</span></h4>\n              <div class=\"meowdb-rel-edit-grid meowdb-bento-grid meowdb-bento-appearance\">\n                <div\n                  v-for=\"field in appearanceFields\"\n                  :key=\"field.key\"\n                  class=\"meowdb-edit-cell\"\n                  :class=\"[\n                    'meowdb-bento-cell',\n                    getFieldClass('appearance', field.key),\n                    { 'is-manual': isFieldManual(field.key), 'is-pending': isFieldPending(field.key) },\n                  ]\"\n                >\n                  <label>{{ field.label }}</label>\n                  <input class=\"meowdb-input\" v-model=\"draft[field.key]\" />\n                </div>\n              </div>\n            </section>\n          </article>\n        </aside>\n      </Transition>\n    </template>\n  </section>\n</template>\n\n<script setup lang=\"ts\">\nimport { runManualAiUpdate } from '@/modules/ai-updater';\nimport { getCurrentEntry, saveCurrentEntry } from '@/modules/data-manager';\nimport { useSettingsStore } from '@/store/settings';\nimport type { CharacterRelation } from '@/type/meowdb';\nimport { storeToRefs } from 'pinia';\n\ntype VisualTab = 'status' | 'relations' | 'settings';\n\ninterface EditableField {\n  key: string;\n  label: string;\n  type?: 'text' | 'number';\n}\n\nconst defaultPalette = ['#7dd3fc', '#f9a8d4', '#86efac', '#fcd34d', '#c4b5fd'];\n\nconst coreFields: EditableField[] = [\n  { key: 'gender', label: '性别' },\n  { key: 'birthday', label: '生日' },\n  { key: 'genitalStatus', label: '性器官及状态' },\n  { key: 'identity', label: '身份' },\n  { key: 'personality', label: '核心人格' },\n  { key: 'sexExp', label: '性经验' },\n  { key: 'coordinate', label: '当前位置' },\n  { key: 'action', label: '实时动作' },\n  { key: 'bond', label: '当前羁绊' },\n  { key: 'favorBase', label: '好感基础值', type: 'number' },\n  { key: 'favorDelta', label: '好感增减值', type: 'number' },\n  { key: 'favorChange', label: '增减原因' },\n  { key: 'clothing', label: '服饰总览' },\n  { key: 'appearance', label: '外貌总览' },\n];\n\nconst clothingFields: EditableField[] = [\n  { key: 'clothingParts.headwear', label: '头饰' },\n  { key: 'clothingParts.jewelry', label: '首饰' },\n  { key: 'clothingParts.facewear', label: '面饰' },\n  { key: 'clothingParts.upper', label: '上装' },\n  { key: 'clothingParts.lower', label: '下装' },\n  { key: 'clothingParts.underwearTop', label: '内衣' },\n  { key: 'clothingParts.underwearBottom', label: '内裤' },\n  { key: 'clothingParts.shoesSocks', label: '鞋袜' },\n];\n\nconst appearanceFields: EditableField[] = [\n  { key: 'appearanceParts.hairColor', label: '发色' },\n  { key: 'appearanceParts.eyeColor', label: '瞳色' },\n  { key: 'appearanceParts.height', label: '身高' },\n  { key: 'appearanceParts.bodyType', label: '体型' },\n];\n\nconst { settings } = storeToRefs(useSettingsStore());\nconst entry = ref(getCurrentEntry());\nconst updating = ref(false);\nconst selectedRelation = ref<CharacterRelation | null>(null);\nconst draft = reactive<Record<string, string>>({});\n\nconst activeTab = ref<VisualTab>(normalizeTab(settings.value.visual_active_tab));\nconst panelCollapsed = ref(Boolean(settings.value.visual_panel_collapsed));\nconst paletteValues = ref<string[]>([...defaultPalette]);\n\nconst relations = computed(() => entry.value?.relations ?? []);\n\nconst relationGridClass = computed(() => {\n  const count = relations.value.length;\n  if (count <= 1) return 'cols-1';\n  if (count <= 4) return 'cols-2';\n  if (count <= 6) return 'cols-3';\n  return 'cols-4';\n});\n\nconst selectedIndex = computed(() => {\n  if (!selectedRelation.value) return -1;\n  return relations.value.findIndex(item => item.name === selectedRelation.value?.name);\n});\n\nconst coreRelation = computed(() => {\n  const list = relations.value;\n  if (!list.length) return null;\n  return list.find(item => /<user>|\\buser\\b/i.test(item.name || '')) ?? list[0];\n});\n\nconst graphNodes = computed(() => {\n  const list = relations.value;\n  if (!list.length) return [] as Array<{ name: string; x: number; y: number; isCore: boolean; color: string }>;\n\n  const core = coreRelation.value ?? list[0];\n  const others = list.filter(item => item.name !== core.name);\n  const center = { x: 380, y: 170 };\n\n  const nodes = [{ name: core.name, x: center.x, y: center.y, isCore: true, color: '#7ee7cf' }];\n  const radiusX = 260;\n  const radiusY = 130;\n\n  others.forEach((item, index) => {\n    const angle = (Math.PI * 2 * index) / Math.max(others.length, 1) - Math.PI / 2;\n    nodes.push({\n      name: item.name,\n      x: center.x + Math.cos(angle) * radiusX,\n      y: center.y + Math.sin(angle) * radiusY,\n      isCore: false,\n      color: pickColor(item.name),\n    });\n  });\n\n  return nodes;\n});\n\nconst graphEdges = computed(() => {\n  const nodes = graphNodes.value;\n  const coreNode = nodes.find(node => node.isCore);\n  if (!coreNode) {\n    return [] as Array<{\n      id: string;\n      from: { x: number; y: number };\n      to: { x: number; y: number };\n      label: string;\n      labelX: number;\n      labelY: number;\n    }>;\n  }\n\n  return nodes\n    .filter(node => !node.isCore)\n    .map(node => {\n      const relation = relations.value.find(item => item.name === node.name);\n      const label = relation?.bond || '关联';\n      return {\n        id: `${coreNode.name}->${node.name}`,\n        from: { x: coreNode.x, y: coreNode.y },\n        to: { x: node.x, y: node.y },\n        label,\n        labelX: (coreNode.x + node.x) / 2,\n        labelY: (coreNode.y + node.y) / 2,\n      };\n    });\n});\n\nconst sceneText = computed(() => {\n  const scene = entry.value?.scene;\n  if (!scene) return '未设置';\n  return `${scene.main} - ${scene.sub}（停留回合：${scene.stayRounds}）`;\n});\n\nconst nsfwText = computed(() => {\n  const nsfw = entry.value?.nsfw;\n  if (!nsfw) return '0/0';\n  return `${nsfw.current}/${nsfw.max}`;\n});\n\nconst hasStatusData = computed(() => {\n  const e = entry.value;\n  if (!e) return false;\n  return Boolean(e.time || e.plot || e.scene?.main || e.scene?.sub || e.nsfw);\n});\n\nconst allFields = computed(() => [...coreFields, ...clothingFields, ...appearanceFields]);\n\nconst pendingChanges = computed(() => {\n  if (!selectedRelation.value) return [] as string[];\n\n  return allFields.value\n    .filter(field => {\n      const oldValue = getByPath(selectedRelation.value as Record<string, any>, field.key);\n      const draftValue = coerceByType(draft[field.key], field.type);\n      return !Object.is(oldValue, draftValue);\n    })\n    .map(field => field.key);\n});\n\nconst manualFields = computed(() => {\n  if (!selectedRelation.value) return [] as string[];\n  return Object.keys(selectedRelation.value.manualEdited ?? {}).filter(\n    key => selectedRelation.value?.manualEdited?.[key],\n  );\n});\n\nwatch(activeTab, tab => {\n  settings.value.visual_active_tab = tab;\n});\n\nwatch(panelCollapsed, collapsed => {\n  settings.value.visual_panel_collapsed = collapsed;\n});\n\nwatch(\n  () => settings.value.relation_colors,\n  next => {\n    const list = Array.isArray(next) ? next.slice(0, 5) : [];\n    while (list.length < 5) list.push(defaultPalette[list.length]);\n    paletteValues.value = list;\n  },\n  { immediate: true, deep: true },\n);\n\nwatch(\n  selectedRelation,\n  relation => {\n    Object.keys(draft).forEach(key => delete draft[key]);\n    if (!relation) return;\n\n    allFields.value.forEach(field => {\n      draft[field.key] = String(getByPath(relation as Record<string, any>, field.key) ?? '');\n    });\n  },\n  { immediate: true },\n);\n\nfunction normalizeTab(tab: string | undefined): VisualTab {\n  if (tab === 'relations' || tab === 'settings' || tab === 'status') return tab;\n  return 'status';\n}\n\nfunction toggleCollapse() {\n  panelCollapsed.value = !panelCollapsed.value;\n}\n\nfunction pickColor(name: string): string {\n  const palette = normalizePalette(settings.value.relation_colors);\n  let hash = 0;\n  for (let i = 0; i < name.length; i += 1) {\n    hash = (hash << 5) - hash + name.charCodeAt(i);\n    hash |= 0;\n  }\n  return palette[Math.abs(hash) % palette.length];\n}\n\nfunction normalizePalette(colors: string[] | undefined): string[] {\n  if (!Array.isArray(colors) || colors.length < 5) return defaultPalette;\n  return colors\n    .slice(0, 5)\n    .map((color, idx) => (typeof color === 'string' && color.trim() ? color : defaultPalette[idx]));\n}\n\nfunction applyPaletteColor(index: number) {\n  const next = [...paletteValues.value];\n  while (next.length < 5) next.push(defaultPalette[next.length]);\n  settings.value.relation_colors = next.slice(0, 5);\n}\n\nfunction resetPalette() {\n  paletteValues.value = [...defaultPalette];\n  settings.value.relation_colors = [...defaultPalette];\n}\n\nfunction formatOne(value: number | undefined) {\n  if (typeof value !== 'number' || Number.isNaN(value)) return '0.0';\n  return value.toFixed(1);\n}\n\nfunction formatSigned(value: number | undefined) {\n  if (typeof value !== 'number' || Number.isNaN(value)) return '+0.0';\n  return value >= 0 ? `+${value.toFixed(1)}` : value.toFixed(1);\n}\n\nfunction deltaClass(value: number | undefined) {\n  if (typeof value !== 'number' || Number.isNaN(value) || value === 0) return 'is-flat';\n  return value > 0 ? 'is-up' : 'is-down';\n}\n\nfunction getFavor(relation: CharacterRelation) {\n  return typeof relation.favor === 'number' ? relation.favor : getFavorBase(relation) + getFavorDelta(relation);\n}\n\nfunction getFavorBase(relation: CharacterRelation) {\n  if (typeof relation.favorBase === 'number') return relation.favorBase;\n  if (typeof relation.favor === 'number' && typeof relation.favorDelta === 'number')\n    return relation.favor - relation.favorDelta;\n  return typeof relation.favor === 'number' ? relation.favor : 0;\n}\n\nfunction getFavorDelta(relation: CharacterRelation) {\n  return typeof relation.favorDelta === 'number' ? relation.favorDelta : 0;\n}\n\nfunction summarizeClothing(relation: CharacterRelation) {\n  const parts = relation.clothingParts;\n  if (!parts) return '服饰未记录';\n  return [parts.upper, parts.lower, parts.shoesSocks].filter(Boolean).join(' / ') || '服饰未记录';\n}\n\nfunction summarizeAppearance(relation: CharacterRelation) {\n  const parts = relation.appearanceParts;\n  if (!parts) return '外貌未记录';\n  return [parts.hairColor, parts.eyeColor, parts.height, parts.bodyType].filter(Boolean).join(' / ') || '外貌未记录';\n}\n\nfunction hasManualEdited(relation: CharacterRelation) {\n  return Object.values(relation.manualEdited ?? {}).some(Boolean);\n}\n\nfunction getStickerText(relation: CharacterRelation) {\n  if (hasManualEdited(relation)) return '手动锁定';\n  const delta = getFavorDelta(relation);\n  if (delta >= 0.2) return '升温';\n  if (delta <= -0.2) return '紧张';\n\n  const hint = `${relation.action ?? ''} ${relation.bond ?? ''} ${relation.personality ?? ''}`;\n  if (/观察|试探|打量|克制|防备|谨慎|沉默/.test(hint)) return '观察中';\n  return '观察中';\n}\n\nfunction getStickerClass(relation: CharacterRelation) {\n  const text = getStickerText(relation);\n  if (text === '手动锁定') return 'is-manual';\n  if (text === '升温') return 'is-up';\n  if (text === '紧张') return 'is-down';\n  return 'is-watch';\n}\n\nfunction refresh() {\n  entry.value = getCurrentEntry();\n}\n\nfunction openRelationDetail(relation: CharacterRelation) {\n  selectedRelation.value = relation;\n}\n\nfunction openRelationByName(name: string) {\n  const relation = relations.value.find(item => item.name === name);\n  if (relation) openRelationDetail(relation);\n}\n\nfunction selectPrev() {\n  if (selectedIndex.value <= 0) return;\n  selectedRelation.value = relations.value[selectedIndex.value - 1] ?? null;\n}\n\nfunction selectNext() {\n  if (selectedIndex.value < 0 || selectedIndex.value >= relations.value.length - 1) return;\n  selectedRelation.value = relations.value[selectedIndex.value + 1] ?? null;\n}\n\nfunction getFieldClass(section: 'core' | 'clothing' | 'appearance', key: string) {\n  if (section == 'core') {\n    if (key == 'bond' || key == 'favorChange' || key == 'clothing' || key == 'appearance') return 'is-wide';\n    if (key == 'action' || key == 'coordinate') return 'is-mid';\n    return 'is-compact';\n  }\n\n  if (section == 'clothing') {\n    if (key.endsWith('upper') || key.endsWith('lower') || key.endsWith('shoesSocks')) return 'is-mid';\n    return 'is-compact';\n  }\n\n  if (section == 'appearance') {\n    if (key.endsWith('height') || key.endsWith('bodyType')) return 'is-mid';\n    return 'is-compact';\n  }\n\n  return 'is-compact';\n}\n\nfunction isFieldManual(path: string) {\n  return Boolean(selectedRelation.value?.manualEdited?.[path]);\n}\n\nfunction isFieldPending(path: string) {\n  return pendingChanges.value.includes(path);\n}\n\nfunction coerceByType(value: string, type: EditableField['type']) {\n  if (type !== 'number') return value ?? '';\n  const n = Number(value);\n  return Number.isFinite(n) ? n : 0;\n}\n\nasync function savePendingChanges() {\n  if (!entry.value || !selectedRelation.value) return;\n  const index = selectedIndex.value;\n  if (index < 0) return;\n\n  const relation = entry.value.relations[index];\n  for (const key of pendingChanges.value) {\n    const field = allFields.value.find(item => item.key === key);\n    const oldValue = getByPath(relation as Record<string, any>, key);\n    const newValue = coerceByType(draft[key], field?.type);\n\n    if (relation.aiBaseline[key] === undefined && (typeof oldValue === 'string' || typeof oldValue === 'number')) {\n      relation.aiBaseline[key] = oldValue;\n    }\n\n    setByPath(relation as Record<string, any>, key, newValue);\n    relation.manualEdited[key] = true;\n  }\n\n  normalizeFavorFields(relation);\n  await persistEntry(relation.name);\n}\n\nasync function restoreAllManualFields() {\n  if (!entry.value || !selectedRelation.value) return;\n  const index = selectedIndex.value;\n  if (index < 0) return;\n\n  const relation = entry.value.relations[index];\n  for (const key of Object.keys(relation.manualEdited ?? {})) {\n    if (!relation.manualEdited[key]) continue;\n    const baseline = relation.aiBaseline?.[key];\n    if (baseline !== undefined) {\n      setByPath(relation as Record<string, any>, key, baseline);\n      draft[key] = String(baseline);\n    }\n    delete relation.manualEdited[key];\n    delete relation.aiBaseline[key];\n  }\n\n  normalizeFavorFields(relation);\n  await persistEntry(relation.name);\n}\n\nfunction normalizeFavorFields(relation: CharacterRelation) {\n  const base = Number(relation.favorBase ?? 0);\n  const delta = Number(relation.favorDelta ?? 0);\n  relation.favorBase = Number.isFinite(base) ? Number(base.toFixed(1)) : 0;\n  relation.favorDelta = Number.isFinite(delta) ? Number(delta.toFixed(1)) : 0;\n  relation.favor = Number((relation.favorBase + relation.favorDelta).toFixed(1));\n}\n\nfunction getByPath(target: Record<string, any>, path: string) {\n  return path.split('.').reduce<any>((acc, key) => (acc == null ? undefined : acc[key]), target);\n}\n\nfunction setByPath(target: Record<string, any>, path: string, value: unknown) {\n  const keys = path.split('.');\n  const last = keys.pop();\n  if (!last) return;\n\n  let cursor: Record<string, any> = target;\n  for (const key of keys) {\n    if (cursor[key] == null || typeof cursor[key] !== 'object') cursor[key] = {};\n    cursor = cursor[key];\n  }\n  cursor[last] = value;\n}\n\nasync function persistEntry(activeName?: string) {\n  if (!entry.value) return;\n  const ok = await saveCurrentEntry(entry.value);\n  if (!ok) {\n    toastr.error('保存失败，字段值不合法');\n    return;\n  }\n\n  refresh();\n  if (activeName) {\n    selectedRelation.value = relations.value.find(item => item.name === activeName) ?? null;\n  }\n}\n\nasync function manualUpdate() {\n  if (updating.value) return;\n  updating.value = true;\n\n  const result = await runManualAiUpdate();\n  updating.value = false;\n\n  if (!result.ok) {\n    toastr.error(result.error || 'AI 更新失败');\n    return;\n  }\n\n  refresh();\n  toastr.success('AI 更新完成');\n}\n\nfunction onDataUpdated() {\n  refresh();\n}\n\nonMounted(() => {\n  window.addEventListener('meowdb:data-updated', onDataUpdated);\n});\n\nonBeforeUnmount(() => {\n  window.removeEventListener('meowdb:data-updated', onDataUpdated);\n});\n</script>\n","import VisualPanel from '@/ui/panel/Panel.vue';\n\nlet app: ReturnType<typeof createApp> | null = null;\nlet mountedEl: Element | null = null;\n\nexport function renderPanel(target: HTMLElement) {\n  if (mountedEl === target && app) return;\n\n  if (app) {\n    app.unmount();\n    app = null;\n    mountedEl = null;\n  }\n\n  target.innerHTML = '';\n  app = createApp(VisualPanel);\n  app.use(createPinia());\n  app.mount(target);\n  mountedEl = target;\n}\n\nexport function unmountPanel() {\n  if (!app) return;\n  app.unmount();\n  app = null;\n  mountedEl = null;\n}\n","import { extension_settings } from '@sillytavern/scripts/extensions';\nimport { setting_field } from '@/type/settings';\nimport { ensurePanelContainer, remountPanelContainer, removePanelContainer } from '@/ui/panel/container';\nimport { renderPanel, unmountPanel } from '@/ui/panel/renderer';\n\nlet observer: MutationObserver | null = null;\n\nexport function initPanel() {\n  if (!isPanelEnabled()) {\n    unmountPanel();\n    removePanelContainer();\n    observeChatChanges();\n    return;\n  }\n\n  const container = ensurePanelContainer();\n  renderPanel(container);\n  observeChatChanges();\n}\n\nfunction observeChatChanges() {\n  if (observer) return;\n\n  observer = new MutationObserver(() => {\n    if (!isPanelEnabled()) {\n      unmountPanel();\n      removePanelContainer();\n      return;\n    }\n\n    const container = remountPanelContainer();\n    if (container) {\n      renderPanel(container);\n      return;\n    }\n\n    const freshContainer = ensurePanelContainer();\n    renderPanel(freshContainer);\n  });\n\n  observer.observe(document.body, {\n    childList: true,\n    subtree: true,\n  });\n}\n\nfunction isPanelEnabled(): boolean {\n  const rawSettings = _.get(extension_settings, setting_field) as { enabled?: boolean } | undefined;\n  return rawSettings?.enabled !== false;\n}\n","import type { MeowDBEntry } from '@/type/meowdb';\n\nexport const sampleEntry: MeowDBEntry = {\n  serial: '🐾喵喵摘要-001',\n  time: '2026-03-19 星期四 | 21:30 微雨',\n  nsfw: {\n    current: 3,\n    max: 20,\n    details: {\n      intensity: 'low',\n      note: 'debug-sample',\n    },\n  },\n  scene: {\n    main: '新婚公寓',\n    sub: '客厅沙发区',\n    stayRounds: 2,\n    topic: '婚后第一夜的微醺对话',\n  },\n  plot: '婚礼结束后，角色们回到家中休息。氛围由热闹转向私密，主要互动集中在放松、回顾婚礼细节与确认彼此边界。',\n  relations: [\n    {\n      name: '<user>',\n      gender: '未知',\n      birthday: '09-17',\n      genitalStatus: '未公开',\n      identity: '主视角',\n      personality: '稳重、克制',\n      sexExp: 'Ghost(1)',\n      coordinate: '客厅沙发左侧',\n      clothing: '礼服外套半解，衬衫，长裤，袜，婚戒',\n      clothingParts: {\n        headwear: '无',\n        jewelry: '婚戒',\n        facewear: '无',\n        upper: '礼服外套半解、衬衫',\n        lower: '长裤',\n        underwearTop: '未记录',\n        underwearBottom: '未记录',\n        shoesSocks: '深色袜',\n      },\n      appearance: '黑发，灰瞳，中等身高，偏瘦',\n      appearanceParts: {\n        hairColor: '黑色',\n        eyeColor: '灰色',\n        height: '178cm',\n        bodyType: '偏瘦',\n      },\n      action: '端着温水，侧身倾听',\n      bond: '新婚伴侣的信任建立期',\n      favor: 6.2,\n      favorBase: 6.0,\n      favorDelta: 0.2,\n      favorChange: '耐心倾听并主动照顾对方情绪',\n      manualEdited: {\n        'appearanceParts.eyeColor': true,\n      },\n      aiBaseline: {\n        'appearanceParts.eyeColor': '???',\n      },\n    },\n    {\n      name: 'Ghost - 婚后',\n      gender: '男',\n      birthday: '02-11',\n      genitalStatus: '放松状态',\n      identity: '伴侣',\n      personality: '外冷内热，防御心较强',\n      sexExp: '<user>(1)',\n      coordinate: '客厅沙发右侧',\n      clothing: '白衬衫，领带松开，西裤，内衣，耳饰，婚戒',\n      clothingParts: {\n        headwear: '无',\n        jewelry: '耳饰、婚戒',\n        facewear: '无',\n        upper: '白衬衫、松开领带',\n        lower: '西裤',\n        underwearTop: '白色内衣',\n        underwearBottom: '未记录',\n        shoesSocks: '短袜',\n      },\n      appearance: '浅金发，琥珀瞳，高挑，匀称',\n      appearanceParts: {\n        hairColor: '浅金色',\n        eyeColor: '琥珀色',\n        height: '184cm',\n        bodyType: '匀称偏精瘦',\n      },\n      action: '靠近并观察对方反应',\n      bond: '由热恋转向长期承诺的磨合期',\n      favor: 7.1,\n      favorBase: 6.8,\n      favorDelta: 0.3,\n      favorChange: '对方主动示弱并分享真实想法',\n      manualEdited: {},\n      aiBaseline: {},\n    },\n\n    {\n      name: '?? - Liao',\n      gender: '?',\n      birthday: '11-05',\n      genitalStatus: '???',\n      identity: '????',\n      personality: '?????',\n      sexExp: '???',\n      coordinate: '????',\n      clothing: '????????????',\n      clothingParts: {\n        headwear: '???',\n        jewelry: '??',\n        facewear: '?',\n        upper: '?????????',\n        lower: '???',\n        underwearTop: '???',\n        underwearBottom: '???',\n        shoesSocks: '??????',\n      },\n      appearance: '????????????????',\n      appearanceParts: {\n        hairColor: '???',\n        eyeColor: '??',\n        height: '176cm',\n        bodyType: '??',\n      },\n      action: '?????????',\n      bond: '??????????',\n      favor: 4.8,\n      favorBase: 5.2,\n      favorDelta: -0.4,\n      favorChange: '???????????????',\n      manualEdited: {},\n      aiBaseline: {},\n    },\n  ],\n  echoes: [\n    {\n      character: 'Ghost - 婚后',\n      content: '周末一起整理婚礼相册并挑选装裱照片。',\n    },\n  ],\n  archived: [\n    {\n      name: '婚礼主持人',\n      location: '已离场',\n      trigger: '查看婚礼录像时可再次提及',\n    },\n  ],\n  enigmas: [\n    {\n      content: 'Ghost 对“家庭责任”的焦虑来源尚未完全公开',\n      progress: 25,\n      related: ['Ghost - 婚后', '<user>'],\n    },\n  ],\n  seeds: [\n    {\n      type: 'soul',\n      name: '誓词背后的真实愿望',\n      bloom: 2,\n      suspense: '谁先提出长期边界协商',\n      driveLink: '信任与责任冲突',\n    },\n    {\n      type: 'world',\n      name: '婚后社交圈压力',\n      bloom: 1,\n      suspense: '外部关系会否影响二人相处节奏',\n      driveLink: '家庭与社交期待',\n    },\n  ],\n};\n","<template>\n  <div class=\"meowdb-drawer-body\">\n    <div class=\"drawer-header\">\n      <div class=\"meowdb-title\">\n        <i class=\"fa-solid fa-paw\"></i>\n        MeowDB 喵喵表格\n      </div>\n      <span class=\"meowdb-version\">v0.3</span>\n    </div>\n\n    <div class=\"meowdb-tabs meowdb-tabs-modal\">\n      <button\n        class=\"meowdb-tab-btn\"\n        :class=\"{ active: activeTab === 'settings' }\"\n        type=\"button\"\n        @click=\"activeTab = 'settings'\"\n      >\n        <i class=\"fa-solid fa-gear\"></i>\n        <span>设置</span>\n      </button>\n      <button\n        class=\"meowdb-tab-btn\"\n        :class=\"{ active: activeTab === 'prompts' }\"\n        type=\"button\"\n        @click=\"activeTab = 'prompts'\"\n      >\n        <i class=\"fa-solid fa-pen-to-square\"></i>\n        <span>提示词</span>\n      </button>\n      <button class=\"meowdb-tab-btn\" type=\"button\" disabled>\n        <i class=\"fa-solid fa-database\"></i>\n        <span>数据</span>\n      </button>\n    </div>\n\n    <div class=\"meowdb-tab-contents meowdb-modal-content-shell\">\n      <Transition name=\"meowdb-fade\" mode=\"out-in\">\n        <div v-if=\"activeTab === 'settings'\" key=\"settings\" class=\"meowdb-tab-content active\">\n          <section class=\"meowdb-settings-section\">\n            <h4 class=\"meowdb-setting-title\">基础设置</h4>\n            <label class=\"meowdb-setting-row\">\n              <span>启用可视化面板</span>\n              <input v-model=\"settings.enabled\" type=\"checkbox\" class=\"meowdb-check\" />\n            </label>\n            <label class=\"meowdb-setting-row\">\n              <span>自动更新</span>\n              <input v-model=\"settings.auto_update\" type=\"checkbox\" class=\"meowdb-check\" />\n            </label>\n            <label class=\"meowdb-setting-row meowdb-setting-row-compact\">\n              <span>自动更新间隔（回合）</span>\n              <div class=\"meowdb-inline-number\">\n                <input\n                  class=\"meowdb-input meowdb-input--xs\"\n                  v-model.number=\"settings.auto_update_interval\"\n                  type=\"number\"\n                  min=\"1\"\n                />\n                <small>轮</small>\n              </div>\n            </label>\n          </section>\n\n          <section class=\"meowdb-settings-section\">\n            <h4 class=\"meowdb-setting-title\">独立 API</h4>\n            <label class=\"meowdb-setting-row\">\n              <span>启用独立 API</span>\n              <input v-model=\"settings.api_enabled\" type=\"checkbox\" class=\"meowdb-check\" />\n            </label>\n\n            <div class=\"meowdb-profile-toolbar\">\n              <label class=\"meowdb-setting-stack meowdb-profile-field\">\n                <span>配置方案</span>\n                <select class=\"meowdb-input\" v-model=\"settings.api_active_profile_id\">\n                  <option v-for=\"profile in apiProfiles\" :key=\"profile.id\" :value=\"profile.id\">\n                    {{ profile.name }}\n                  </option>\n                </select>\n              </label>\n            </div>\n\n            <div class=\"meowdb-setting-actions\">\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"openProfileEditor('create')\">\n                新建方案\n              </button>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"openProfileEditor('rename')\">\n                重命名\n              </button>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"updateCurrentProfile\">保存方案</button>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"exportCurrentProfile\">导出</button>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"triggerImportProfile\">导入</button>\n              <button\n                class=\"menu_button meowdb-tool-btn danger\"\n                type=\"button\"\n                :disabled=\"apiProfiles.length <= 1\"\n                @click=\"removeCurrentProfile\"\n              >\n                删除\n              </button>\n              <input\n                ref=\"profileImportInput\"\n                type=\"file\"\n                accept=\"application/json,.json\"\n                style=\"display: none\"\n                @change=\"onImportProfileFile\"\n              />\n            </div>\n\n            <Transition name=\"meowdb-fade\">\n              <div v-if=\"profileEditorOpen\" class=\"meowdb-profile-editor\" @keydown.enter.prevent=\"submitProfileEditor\">\n                <label class=\"meowdb-setting-stack\">\n                  <span>{{ profileEditorMode === 'create' ? '输入新方案名称' : '输入新名称' }}</span>\n                  <input\n                    ref=\"profileEditorInput\"\n                    class=\"meowdb-input\"\n                    v-model.trim=\"profileEditorName\"\n                    type=\"text\"\n                    placeholder=\"e.g. OpenRouter-cheap\"\n                  />\n                </label>\n                <div class=\"meowdb-profile-editor-actions\">\n                  <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"submitProfileEditor\">确认</button>\n                  <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"closeProfileEditor\">取消</button>\n                </div>\n              </div>\n            </Transition>\n\n            <div class=\"meowdb-setting-grid-2\">\n              <label class=\"meowdb-setting-row meowdb-setting-stack\">\n                <span>API URL</span>\n                <input\n                  class=\"meowdb-input\"\n                  v-model=\"settings.api_url\"\n                  type=\"text\"\n                  placeholder=\"https://api.openai.com/v1\"\n                />\n              </label>\n              <label class=\"meowdb-setting-row meowdb-setting-stack\">\n                <span>API Key</span>\n                <input class=\"meowdb-input\" v-model=\"settings.api_key\" type=\"password\" placeholder=\"sk-...\" />\n              </label>\n            </div>\n\n            <label class=\"meowdb-setting-row meowdb-setting-stack\">\n              <span>模型</span>\n              <div class=\"meowdb-model-row\">\n                <input\n                  class=\"meowdb-input\"\n                  v-model=\"settings.api_model\"\n                  type=\"text\"\n                  list=\"meowdb-model-options\"\n                  placeholder=\"gpt-4.1-mini\"\n                />\n                <button\n                  class=\"menu_button meowdb-tool-btn\"\n                  type=\"button\"\n                  :disabled=\"fetchingModels\"\n                  @click=\"fetchModels\"\n                >\n                  {{ fetchingModels ? '拉取中...' : '手动拉取模型' }}\n                </button>\n                <button\n                  class=\"menu_button meowdb-tool-btn\"\n                  type=\"button\"\n                  :disabled=\"testingConnection\"\n                  @click=\"testConnection\"\n                >\n                  {{ testingConnection ? '测试中...' : '连接测试' }}\n                </button>\n              </div>\n              <datalist id=\"meowdb-model-options\">\n                <option v-for=\"model in modelOptions\" :key=\"model\" :value=\"model\" />\n              </datalist>\n            </label>\n\n            <div class=\"meowdb-setting-grid-2\">\n              <label class=\"meowdb-setting-row meowdb-setting-stack\">\n                <span>温度</span>\n                <input\n                  class=\"meowdb-input meowdb-input--xs\"\n                  v-model.number=\"settings.api_temperature\"\n                  type=\"number\"\n                  min=\"0\"\n                  max=\"2\"\n                  step=\"0.1\"\n                />\n              </label>\n              <label class=\"meowdb-setting-row meowdb-setting-stack\">\n                <span>最大上下文长度</span>\n                <input\n                  class=\"meowdb-input meowdb-input--xs\"\n                  v-model.number=\"settings.api_max_tokens\"\n                  type=\"number\"\n                  min=\"128\"\n                  step=\"64\"\n                />\n              </label>\n            </div>\n          </section>\n\n          <hr class=\"sysHR\" />\n\n          <div class=\"meowdb-tools\">\n            <button class=\"menu_button meowdb-tool-btn\" :disabled=\"injecting\" @click=\"injectSample\">\n              {{ injecting ? '注入中...' : '注入示例数据' }}\n            </button>\n            <button class=\"menu_button meowdb-tool-btn danger\" :disabled=\"clearing\" @click=\"clearAll\">\n              {{ clearing ? '清空中...' : '清空当前聊天数据' }}\n            </button>\n          </div>\n        </div>\n\n        <div v-else key=\"prompts\" class=\"meowdb-tab-content active\">\n          <section class=\"meowdb-prompt-card\">\n            <header class=\"meowdb-prompt-card-head\">\n              <div>\n                <h4>Relations 更新提示词</h4>\n                <p>用于 AI 更新角色关系、服饰/外貌拆解和手动字段保护逻辑。</p>\n              </div>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"restoreRelationsPrompt\">\n                恢复默认\n              </button>\n            </header>\n\n            <textarea\n              class=\"meowdb-input meowdb-prompt-textarea\"\n              v-model=\"settings.relations_prompt\"\n              rows=\"18\"\n              placeholder=\"留空将使用默认 relations 提示词\"\n            />\n\n            <div class=\"meowdb-prompt-meta\">\n              <span>字符数：{{ settings.relations_prompt?.length || 0 }}</span>\n              <span>留空 = 使用内置默认</span>\n            </div>\n          </section>\n        </div>\n      </Transition>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { sampleEntry } from '@/data/sample-entry';\nimport { DEFAULT_RELATIONS_PROMPT } from '@/modules/ai-updater/prompt-builder';\nimport { clearAllEntries, saveCurrentEntry } from '@/modules/data-manager';\nimport { useSettingsStore } from '@/store/settings';\nimport { storeToRefs } from 'pinia';\n\ninterface ApiProfile {\n  id: string;\n  name: string;\n  enabled: boolean;\n  url: string;\n  key: string;\n  model: string;\n  temperature: number;\n  max_tokens: number;\n}\n\nconst { settings } = storeToRefs(useSettingsStore());\nconst activeTab = ref<'settings' | 'prompts'>('settings');\nconst injecting = ref(false);\nconst clearing = ref(false);\nconst fetchingModels = ref(false);\nconst testingConnection = ref(false);\nconst modelOptions = ref<string[]>([]);\nconst profileImportInput = ref<HTMLInputElement | null>(null);\nconst profileEditorInput = ref<HTMLInputElement | null>(null);\nconst profileEditorOpen = ref(false);\nconst profileEditorMode = ref<'create' | 'rename'>('create');\nconst profileEditorName = ref('');\n\nconst apiProfiles = computed<ApiProfile[]>(() => settings.value.api_profiles as ApiProfile[]);\nconst activeProfile = computed<ApiProfile | null>(() => {\n  const id = settings.value.api_active_profile_id;\n  return apiProfiles.value.find(item => item.id === id) ?? null;\n});\n\nfunction makeProfileId() {\n  return `api_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`;\n}\n\nfunction createProfile(name?: string): ApiProfile {\n  return {\n    id: makeProfileId(),\n    name: name?.trim() || `配置 ${apiProfiles.value.length + 1}`,\n    enabled: Boolean(settings.value.api_enabled),\n    url: settings.value.api_url || '',\n    key: settings.value.api_key || '',\n    model: settings.value.api_model || '',\n    temperature: Number(settings.value.api_temperature || 0.7),\n    max_tokens: Number(settings.value.api_max_tokens || 1200),\n  };\n}\n\nfunction ensureProfiles() {\n  if (!Array.isArray(settings.value.api_profiles)) settings.value.api_profiles = [];\n  if (settings.value.api_profiles.length === 0) settings.value.api_profiles.push(createProfile('默认配置'));\n\n  const exists = settings.value.api_profiles.some(item => item.id === settings.value.api_active_profile_id);\n  if (!exists) settings.value.api_active_profile_id = settings.value.api_profiles[0]?.id || '';\n}\n\nfunction applyProfileToFields(profile: ApiProfile | null) {\n  if (!profile) return;\n  settings.value.api_enabled = profile.enabled;\n  settings.value.api_url = profile.url;\n  settings.value.api_key = profile.key;\n  settings.value.api_model = profile.model;\n  settings.value.api_temperature = profile.temperature;\n  settings.value.api_max_tokens = profile.max_tokens;\n}\n\nfunction syncFieldsToActiveProfile() {\n  if (!activeProfile.value) return;\n  activeProfile.value.enabled = Boolean(settings.value.api_enabled);\n  activeProfile.value.url = settings.value.api_url || '';\n  activeProfile.value.key = settings.value.api_key || '';\n  activeProfile.value.model = settings.value.api_model || '';\n  activeProfile.value.temperature = Number(settings.value.api_temperature || 0.7);\n  activeProfile.value.max_tokens = Number(settings.value.api_max_tokens || 1200);\n}\n\nfunction saveAsNewProfile(name: string) {\n  const profile = createProfile(name);\n  settings.value.api_profiles.push(profile);\n  settings.value.api_active_profile_id = profile.id;\n  toastr.success('已创建新方案');\n}\n\nfunction renameCurrentProfile(name: string) {\n  if (!activeProfile.value) return;\n  activeProfile.value.name = name.trim() || activeProfile.value.name;\n  toastr.success('方案已重命名');\n}\n\nfunction openProfileEditor(mode: 'create' | 'rename') {\n  profileEditorMode.value = mode;\n  profileEditorName.value = mode === 'rename' ? activeProfile.value?.name || '' : '';\n  profileEditorOpen.value = true;\n  nextTick(() => profileEditorInput.value?.focus());\n}\n\nfunction closeProfileEditor() {\n  profileEditorOpen.value = false;\n  profileEditorName.value = '';\n}\n\nfunction submitProfileEditor() {\n  const name = profileEditorName.value.trim();\n  if (!name) {\n    toastr.warning('请输入方案名称');\n    return;\n  }\n\n  if (profileEditorMode.value === 'create') {\n    saveAsNewProfile(name);\n  } else {\n    renameCurrentProfile(name);\n  }\n\n  closeProfileEditor();\n}\n\nfunction updateCurrentProfile() {\n  syncFieldsToActiveProfile();\n  toastr.success('当前方案已保存');\n}\n\nfunction removeCurrentProfile() {\n  if (settings.value.api_profiles.length <= 1) return;\n  const id = settings.value.api_active_profile_id;\n  settings.value.api_profiles = settings.value.api_profiles.filter(item => item.id !== id);\n  settings.value.api_active_profile_id = settings.value.api_profiles[0]?.id || '';\n  applyProfileToFields(activeProfile.value);\n  toastr.success('已删除当前方案');\n}\n\nfunction exportCurrentProfile() {\n  if (!activeProfile.value) return;\n  const payload = {\n    ...activeProfile.value,\n    exportedAt: new Date().toISOString(),\n    format: 'meowdb-api-profile-v1',\n  };\n\n  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json;charset=utf-8' });\n  const url = URL.createObjectURL(blob);\n  const safeName = (activeProfile.value.name || 'api-profile').replace(/[^a-zA-Z0-9\\u4e00-\\u9fa5-_]/g, '_');\n  const a = document.createElement('a');\n  a.href = url;\n  a.download = `meowdb-${safeName}.json`;\n  document.body.appendChild(a);\n  a.click();\n  document.body.removeChild(a);\n  URL.revokeObjectURL(url);\n  toastr.success('已导出当前方案');\n}\n\nfunction triggerImportProfile() {\n  profileImportInput.value?.click();\n}\n\nasync function onImportProfileFile(event: Event) {\n  const input = event.target as HTMLInputElement;\n  const file = input.files?.[0];\n  if (!file) return;\n\n  try {\n    const text = await file.text();\n    const data = JSON.parse(text) as Partial<ApiProfile>;\n\n    const profile: ApiProfile = {\n      id: makeProfileId(),\n      name: (data.name || file.name.replace(/\\.json$/i, '') || '导入方案').trim(),\n      enabled: Boolean(data.enabled),\n      url: String(data.url || ''),\n      key: String(data.key || ''),\n      model: String(data.model || ''),\n      temperature: Number(data.temperature ?? 0.7),\n      max_tokens: Number(data.max_tokens ?? 1200),\n    };\n\n    if (!Number.isFinite(profile.temperature)) profile.temperature = 0.7;\n    if (!Number.isFinite(profile.max_tokens) || profile.max_tokens <= 0) profile.max_tokens = 1200;\n\n    settings.value.api_profiles.push(profile);\n    settings.value.api_active_profile_id = profile.id;\n    applyProfileToFields(profile);\n    toastr.success('方案导入成功');\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(`导入失败：${message}`);\n  } finally {\n    input.value = '';\n  }\n}\n\nfunction normalizeUrl(url: string) {\n  return url.trim().replace(/\\/$/, '');\n}\n\nasync function fetchModels() {\n  const url = normalizeUrl(settings.value.api_url);\n  if (!url) {\n    toastr.warning('请先填写 API URL');\n    return;\n  }\n\n  fetchingModels.value = true;\n  try {\n    const response = await fetch(`${url}/models`, {\n      headers: {\n        ...(settings.value.api_key ? { Authorization: `Bearer ${settings.value.api_key}` } : {}),\n      },\n    });\n\n    if (!response.ok) {\n      const reason = await response.text();\n      throw new Error(reason || `HTTP ${response.status}`);\n    }\n\n    const data = (await response.json()) as { data?: Array<{ id?: string }> };\n    const ids = (data.data ?? []).map(item => item.id).filter((item): item is string => Boolean(item));\n\n    if (ids.length === 0) {\n      toastr.warning('未拉取到模型列表');\n      return;\n    }\n\n    modelOptions.value = ids;\n    if (!settings.value.api_model) settings.value.api_model = ids[0];\n    syncFieldsToActiveProfile();\n    toastr.success(`已拉取 ${ids.length} 个模型`);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(`拉取模型失败：${message}`);\n  } finally {\n    fetchingModels.value = false;\n  }\n}\n\nasync function testConnection() {\n  const url = normalizeUrl(settings.value.api_url);\n  if (!url) {\n    toastr.warning('请先填写 API URL');\n    return;\n  }\n\n  testingConnection.value = true;\n  try {\n    const response = await fetch(`${url}/models`, {\n      headers: {\n        ...(settings.value.api_key ? { Authorization: `Bearer ${settings.value.api_key}` } : {}),\n      },\n    });\n\n    if (!response.ok) {\n      const reason = await response.text();\n      throw new Error(reason || `HTTP ${response.status}`);\n    }\n\n    toastr.success('连接测试成功');\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(`连接测试失败：${message}`);\n  } finally {\n    testingConnection.value = false;\n  }\n}\n\nasync function injectSample() {\n  if (injecting.value) return;\n  injecting.value = true;\n\n  const ok = await saveCurrentEntry(sampleEntry);\n  injecting.value = false;\n\n  if (!ok) {\n    toastr.error('示例数据注入失败');\n    return;\n  }\n\n  toastr.success('示例数据已注入');\n}\n\nasync function clearAll() {\n  if (clearing.value) return;\n  clearing.value = true;\n\n  const cleared = await clearAllEntries();\n  clearing.value = false;\n\n  toastr.success(cleared > 0 ? `已清空 ${cleared} 条 MeowDB 数据` : '当前聊天没有可清空的 MeowDB 数据');\n}\n\nfunction restoreRelationsPrompt() {\n  settings.value.relations_prompt = DEFAULT_RELATIONS_PROMPT;\n  toastr.success('已还原默认 relations 提示词');\n}\n\nwatch(\n  () => settings.value.api_active_profile_id,\n  () => {\n    ensureProfiles();\n    applyProfileToFields(activeProfile.value);\n  },\n  { immediate: true },\n);\n\nwatch(\n  () => [\n    settings.value.api_enabled,\n    settings.value.api_url,\n    settings.value.api_key,\n    settings.value.api_model,\n    settings.value.api_temperature,\n    settings.value.api_max_tokens,\n  ],\n  () => syncFieldsToActiveProfile(),\n);\n\nonMounted(() => {\n  ensureProfiles();\n  applyProfileToFields(activeProfile.value);\n});\n</script>\n","<template>\n  <div class=\"meowdb-drawer-body\">\n    <div class=\"drawer-header\">\n      <div class=\"meowdb-title\">\n        <i class=\"fa-solid fa-paw\"></i>\n        MeowDB 喵喵表格\n      </div>\n      <span class=\"meowdb-version\">v0.3</span>\n    </div>\n\n    <div class=\"meowdb-tabs meowdb-tabs-modal\">\n      <button\n        class=\"meowdb-tab-btn\"\n        :class=\"{ active: activeTab === 'settings' }\"\n        type=\"button\"\n        @click=\"activeTab = 'settings'\"\n      >\n        <i class=\"fa-solid fa-gear\"></i>\n        <span>设置</span>\n      </button>\n      <button\n        class=\"meowdb-tab-btn\"\n        :class=\"{ active: activeTab === 'prompts' }\"\n        type=\"button\"\n        @click=\"activeTab = 'prompts'\"\n      >\n        <i class=\"fa-solid fa-pen-to-square\"></i>\n        <span>提示词</span>\n      </button>\n      <button class=\"meowdb-tab-btn\" type=\"button\" disabled>\n        <i class=\"fa-solid fa-database\"></i>\n        <span>数据</span>\n      </button>\n    </div>\n\n    <div class=\"meowdb-tab-contents meowdb-modal-content-shell\">\n      <Transition name=\"meowdb-fade\" mode=\"out-in\">\n        <div v-if=\"activeTab === 'settings'\" key=\"settings\" class=\"meowdb-tab-content active\">\n          <section class=\"meowdb-settings-section\">\n            <h4 class=\"meowdb-setting-title\">基础设置</h4>\n            <label class=\"meowdb-setting-row\">\n              <span>启用可视化面板</span>\n              <input v-model=\"settings.enabled\" type=\"checkbox\" class=\"meowdb-check\" />\n            </label>\n            <label class=\"meowdb-setting-row\">\n              <span>自动更新</span>\n              <input v-model=\"settings.auto_update\" type=\"checkbox\" class=\"meowdb-check\" />\n            </label>\n            <label class=\"meowdb-setting-row meowdb-setting-row-compact\">\n              <span>自动更新间隔（回合）</span>\n              <div class=\"meowdb-inline-number\">\n                <input\n                  class=\"meowdb-input meowdb-input--xs\"\n                  v-model.number=\"settings.auto_update_interval\"\n                  type=\"number\"\n                  min=\"1\"\n                />\n                <small>轮</small>\n              </div>\n            </label>\n          </section>\n\n          <section class=\"meowdb-settings-section\">\n            <h4 class=\"meowdb-setting-title\">独立 API</h4>\n            <label class=\"meowdb-setting-row\">\n              <span>启用独立 API</span>\n              <input v-model=\"settings.api_enabled\" type=\"checkbox\" class=\"meowdb-check\" />\n            </label>\n\n            <div class=\"meowdb-profile-toolbar\">\n              <label class=\"meowdb-setting-stack meowdb-profile-field\">\n                <span>配置方案</span>\n                <select class=\"meowdb-input\" v-model=\"settings.api_active_profile_id\">\n                  <option v-for=\"profile in apiProfiles\" :key=\"profile.id\" :value=\"profile.id\">\n                    {{ profile.name }}\n                  </option>\n                </select>\n              </label>\n            </div>\n\n            <div class=\"meowdb-setting-actions\">\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"openProfileEditor('create')\">\n                新建方案\n              </button>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"openProfileEditor('rename')\">\n                重命名\n              </button>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"updateCurrentProfile\">保存方案</button>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"exportCurrentProfile\">导出</button>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"triggerImportProfile\">导入</button>\n              <button\n                class=\"menu_button meowdb-tool-btn danger\"\n                type=\"button\"\n                :disabled=\"apiProfiles.length <= 1\"\n                @click=\"removeCurrentProfile\"\n              >\n                删除\n              </button>\n              <input\n                ref=\"profileImportInput\"\n                type=\"file\"\n                accept=\"application/json,.json\"\n                style=\"display: none\"\n                @change=\"onImportProfileFile\"\n              />\n            </div>\n\n            <Transition name=\"meowdb-fade\">\n              <div v-if=\"profileEditorOpen\" class=\"meowdb-profile-editor\" @keydown.enter.prevent=\"submitProfileEditor\">\n                <label class=\"meowdb-setting-stack\">\n                  <span>{{ profileEditorMode === 'create' ? '输入新方案名称' : '输入新名称' }}</span>\n                  <input\n                    ref=\"profileEditorInput\"\n                    class=\"meowdb-input\"\n                    v-model.trim=\"profileEditorName\"\n                    type=\"text\"\n                    placeholder=\"e.g. OpenRouter-cheap\"\n                  />\n                </label>\n                <div class=\"meowdb-profile-editor-actions\">\n                  <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"submitProfileEditor\">确认</button>\n                  <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"closeProfileEditor\">取消</button>\n                </div>\n              </div>\n            </Transition>\n\n            <div class=\"meowdb-setting-grid-2\">\n              <label class=\"meowdb-setting-row meowdb-setting-stack\">\n                <span>API URL</span>\n                <input\n                  class=\"meowdb-input\"\n                  v-model=\"settings.api_url\"\n                  type=\"text\"\n                  placeholder=\"https://api.openai.com/v1\"\n                />\n              </label>\n              <label class=\"meowdb-setting-row meowdb-setting-stack\">\n                <span>API Key</span>\n                <input class=\"meowdb-input\" v-model=\"settings.api_key\" type=\"password\" placeholder=\"sk-...\" />\n              </label>\n            </div>\n\n            <label class=\"meowdb-setting-row meowdb-setting-stack\">\n              <span>模型</span>\n              <div class=\"meowdb-model-row\">\n                <input\n                  class=\"meowdb-input\"\n                  v-model=\"settings.api_model\"\n                  type=\"text\"\n                  list=\"meowdb-model-options\"\n                  placeholder=\"gpt-4.1-mini\"\n                />\n                <button\n                  class=\"menu_button meowdb-tool-btn\"\n                  type=\"button\"\n                  :disabled=\"fetchingModels\"\n                  @click=\"fetchModels\"\n                >\n                  {{ fetchingModels ? '拉取中...' : '手动拉取模型' }}\n                </button>\n                <button\n                  class=\"menu_button meowdb-tool-btn\"\n                  type=\"button\"\n                  :disabled=\"testingConnection\"\n                  @click=\"testConnection\"\n                >\n                  {{ testingConnection ? '测试中...' : '连接测试' }}\n                </button>\n              </div>\n              <datalist id=\"meowdb-model-options\">\n                <option v-for=\"model in modelOptions\" :key=\"model\" :value=\"model\" />\n              </datalist>\n            </label>\n\n            <div class=\"meowdb-setting-grid-2\">\n              <label class=\"meowdb-setting-row meowdb-setting-stack\">\n                <span>温度</span>\n                <input\n                  class=\"meowdb-input meowdb-input--xs\"\n                  v-model.number=\"settings.api_temperature\"\n                  type=\"number\"\n                  min=\"0\"\n                  max=\"2\"\n                  step=\"0.1\"\n                />\n              </label>\n              <label class=\"meowdb-setting-row meowdb-setting-stack\">\n                <span>最大上下文长度</span>\n                <input\n                  class=\"meowdb-input meowdb-input--xs\"\n                  v-model.number=\"settings.api_max_tokens\"\n                  type=\"number\"\n                  min=\"128\"\n                  step=\"64\"\n                />\n              </label>\n            </div>\n          </section>\n\n          <hr class=\"sysHR\" />\n\n          <div class=\"meowdb-tools\">\n            <button class=\"menu_button meowdb-tool-btn\" :disabled=\"injecting\" @click=\"injectSample\">\n              {{ injecting ? '注入中...' : '注入示例数据' }}\n            </button>\n            <button class=\"menu_button meowdb-tool-btn danger\" :disabled=\"clearing\" @click=\"clearAll\">\n              {{ clearing ? '清空中...' : '清空当前聊天数据' }}\n            </button>\n          </div>\n        </div>\n\n        <div v-else key=\"prompts\" class=\"meowdb-tab-content active\">\n          <section class=\"meowdb-prompt-card\">\n            <header class=\"meowdb-prompt-card-head\">\n              <div>\n                <h4>Relations 更新提示词</h4>\n                <p>用于 AI 更新角色关系、服饰/外貌拆解和手动字段保护逻辑。</p>\n              </div>\n              <button class=\"menu_button meowdb-tool-btn\" type=\"button\" @click=\"restoreRelationsPrompt\">\n                恢复默认\n              </button>\n            </header>\n\n            <textarea\n              class=\"meowdb-input meowdb-prompt-textarea\"\n              v-model=\"settings.relations_prompt\"\n              rows=\"18\"\n              placeholder=\"留空将使用默认 relations 提示词\"\n            />\n\n            <div class=\"meowdb-prompt-meta\">\n              <span>字符数：{{ settings.relations_prompt?.length || 0 }}</span>\n              <span>留空 = 使用内置默认</span>\n            </div>\n          </section>\n        </div>\n      </Transition>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { sampleEntry } from '@/data/sample-entry';\nimport { DEFAULT_RELATIONS_PROMPT } from '@/modules/ai-updater/prompt-builder';\nimport { clearAllEntries, saveCurrentEntry } from '@/modules/data-manager';\nimport { useSettingsStore } from '@/store/settings';\nimport { storeToRefs } from 'pinia';\n\ninterface ApiProfile {\n  id: string;\n  name: string;\n  enabled: boolean;\n  url: string;\n  key: string;\n  model: string;\n  temperature: number;\n  max_tokens: number;\n}\n\nconst { settings } = storeToRefs(useSettingsStore());\nconst activeTab = ref<'settings' | 'prompts'>('settings');\nconst injecting = ref(false);\nconst clearing = ref(false);\nconst fetchingModels = ref(false);\nconst testingConnection = ref(false);\nconst modelOptions = ref<string[]>([]);\nconst profileImportInput = ref<HTMLInputElement | null>(null);\nconst profileEditorInput = ref<HTMLInputElement | null>(null);\nconst profileEditorOpen = ref(false);\nconst profileEditorMode = ref<'create' | 'rename'>('create');\nconst profileEditorName = ref('');\n\nconst apiProfiles = computed<ApiProfile[]>(() => settings.value.api_profiles as ApiProfile[]);\nconst activeProfile = computed<ApiProfile | null>(() => {\n  const id = settings.value.api_active_profile_id;\n  return apiProfiles.value.find(item => item.id === id) ?? null;\n});\n\nfunction makeProfileId() {\n  return `api_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 7)}`;\n}\n\nfunction createProfile(name?: string): ApiProfile {\n  return {\n    id: makeProfileId(),\n    name: name?.trim() || `配置 ${apiProfiles.value.length + 1}`,\n    enabled: Boolean(settings.value.api_enabled),\n    url: settings.value.api_url || '',\n    key: settings.value.api_key || '',\n    model: settings.value.api_model || '',\n    temperature: Number(settings.value.api_temperature || 0.7),\n    max_tokens: Number(settings.value.api_max_tokens || 1200),\n  };\n}\n\nfunction ensureProfiles() {\n  if (!Array.isArray(settings.value.api_profiles)) settings.value.api_profiles = [];\n  if (settings.value.api_profiles.length === 0) settings.value.api_profiles.push(createProfile('默认配置'));\n\n  const exists = settings.value.api_profiles.some(item => item.id === settings.value.api_active_profile_id);\n  if (!exists) settings.value.api_active_profile_id = settings.value.api_profiles[0]?.id || '';\n}\n\nfunction applyProfileToFields(profile: ApiProfile | null) {\n  if (!profile) return;\n  settings.value.api_enabled = profile.enabled;\n  settings.value.api_url = profile.url;\n  settings.value.api_key = profile.key;\n  settings.value.api_model = profile.model;\n  settings.value.api_temperature = profile.temperature;\n  settings.value.api_max_tokens = profile.max_tokens;\n}\n\nfunction syncFieldsToActiveProfile() {\n  if (!activeProfile.value) return;\n  activeProfile.value.enabled = Boolean(settings.value.api_enabled);\n  activeProfile.value.url = settings.value.api_url || '';\n  activeProfile.value.key = settings.value.api_key || '';\n  activeProfile.value.model = settings.value.api_model || '';\n  activeProfile.value.temperature = Number(settings.value.api_temperature || 0.7);\n  activeProfile.value.max_tokens = Number(settings.value.api_max_tokens || 1200);\n}\n\nfunction saveAsNewProfile(name: string) {\n  const profile = createProfile(name);\n  settings.value.api_profiles.push(profile);\n  settings.value.api_active_profile_id = profile.id;\n  toastr.success('已创建新方案');\n}\n\nfunction renameCurrentProfile(name: string) {\n  if (!activeProfile.value) return;\n  activeProfile.value.name = name.trim() || activeProfile.value.name;\n  toastr.success('方案已重命名');\n}\n\nfunction openProfileEditor(mode: 'create' | 'rename') {\n  profileEditorMode.value = mode;\n  profileEditorName.value = mode === 'rename' ? activeProfile.value?.name || '' : '';\n  profileEditorOpen.value = true;\n  nextTick(() => profileEditorInput.value?.focus());\n}\n\nfunction closeProfileEditor() {\n  profileEditorOpen.value = false;\n  profileEditorName.value = '';\n}\n\nfunction submitProfileEditor() {\n  const name = profileEditorName.value.trim();\n  if (!name) {\n    toastr.warning('请输入方案名称');\n    return;\n  }\n\n  if (profileEditorMode.value === 'create') {\n    saveAsNewProfile(name);\n  } else {\n    renameCurrentProfile(name);\n  }\n\n  closeProfileEditor();\n}\n\nfunction updateCurrentProfile() {\n  syncFieldsToActiveProfile();\n  toastr.success('当前方案已保存');\n}\n\nfunction removeCurrentProfile() {\n  if (settings.value.api_profiles.length <= 1) return;\n  const id = settings.value.api_active_profile_id;\n  settings.value.api_profiles = settings.value.api_profiles.filter(item => item.id !== id);\n  settings.value.api_active_profile_id = settings.value.api_profiles[0]?.id || '';\n  applyProfileToFields(activeProfile.value);\n  toastr.success('已删除当前方案');\n}\n\nfunction exportCurrentProfile() {\n  if (!activeProfile.value) return;\n  const payload = {\n    ...activeProfile.value,\n    exportedAt: new Date().toISOString(),\n    format: 'meowdb-api-profile-v1',\n  };\n\n  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json;charset=utf-8' });\n  const url = URL.createObjectURL(blob);\n  const safeName = (activeProfile.value.name || 'api-profile').replace(/[^a-zA-Z0-9\\u4e00-\\u9fa5-_]/g, '_');\n  const a = document.createElement('a');\n  a.href = url;\n  a.download = `meowdb-${safeName}.json`;\n  document.body.appendChild(a);\n  a.click();\n  document.body.removeChild(a);\n  URL.revokeObjectURL(url);\n  toastr.success('已导出当前方案');\n}\n\nfunction triggerImportProfile() {\n  profileImportInput.value?.click();\n}\n\nasync function onImportProfileFile(event: Event) {\n  const input = event.target as HTMLInputElement;\n  const file = input.files?.[0];\n  if (!file) return;\n\n  try {\n    const text = await file.text();\n    const data = JSON.parse(text) as Partial<ApiProfile>;\n\n    const profile: ApiProfile = {\n      id: makeProfileId(),\n      name: (data.name || file.name.replace(/\\.json$/i, '') || '导入方案').trim(),\n      enabled: Boolean(data.enabled),\n      url: String(data.url || ''),\n      key: String(data.key || ''),\n      model: String(data.model || ''),\n      temperature: Number(data.temperature ?? 0.7),\n      max_tokens: Number(data.max_tokens ?? 1200),\n    };\n\n    if (!Number.isFinite(profile.temperature)) profile.temperature = 0.7;\n    if (!Number.isFinite(profile.max_tokens) || profile.max_tokens <= 0) profile.max_tokens = 1200;\n\n    settings.value.api_profiles.push(profile);\n    settings.value.api_active_profile_id = profile.id;\n    applyProfileToFields(profile);\n    toastr.success('方案导入成功');\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(`导入失败：${message}`);\n  } finally {\n    input.value = '';\n  }\n}\n\nfunction normalizeUrl(url: string) {\n  return url.trim().replace(/\\/$/, '');\n}\n\nasync function fetchModels() {\n  const url = normalizeUrl(settings.value.api_url);\n  if (!url) {\n    toastr.warning('请先填写 API URL');\n    return;\n  }\n\n  fetchingModels.value = true;\n  try {\n    const response = await fetch(`${url}/models`, {\n      headers: {\n        ...(settings.value.api_key ? { Authorization: `Bearer ${settings.value.api_key}` } : {}),\n      },\n    });\n\n    if (!response.ok) {\n      const reason = await response.text();\n      throw new Error(reason || `HTTP ${response.status}`);\n    }\n\n    const data = (await response.json()) as { data?: Array<{ id?: string }> };\n    const ids = (data.data ?? []).map(item => item.id).filter((item): item is string => Boolean(item));\n\n    if (ids.length === 0) {\n      toastr.warning('未拉取到模型列表');\n      return;\n    }\n\n    modelOptions.value = ids;\n    if (!settings.value.api_model) settings.value.api_model = ids[0];\n    syncFieldsToActiveProfile();\n    toastr.success(`已拉取 ${ids.length} 个模型`);\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(`拉取模型失败：${message}`);\n  } finally {\n    fetchingModels.value = false;\n  }\n}\n\nasync function testConnection() {\n  const url = normalizeUrl(settings.value.api_url);\n  if (!url) {\n    toastr.warning('请先填写 API URL');\n    return;\n  }\n\n  testingConnection.value = true;\n  try {\n    const response = await fetch(`${url}/models`, {\n      headers: {\n        ...(settings.value.api_key ? { Authorization: `Bearer ${settings.value.api_key}` } : {}),\n      },\n    });\n\n    if (!response.ok) {\n      const reason = await response.text();\n      throw new Error(reason || `HTTP ${response.status}`);\n    }\n\n    toastr.success('连接测试成功');\n  } catch (error) {\n    const message = error instanceof Error ? error.message : String(error);\n    toastr.error(`连接测试失败：${message}`);\n  } finally {\n    testingConnection.value = false;\n  }\n}\n\nasync function injectSample() {\n  if (injecting.value) return;\n  injecting.value = true;\n\n  const ok = await saveCurrentEntry(sampleEntry);\n  injecting.value = false;\n\n  if (!ok) {\n    toastr.error('示例数据注入失败');\n    return;\n  }\n\n  toastr.success('示例数据已注入');\n}\n\nasync function clearAll() {\n  if (clearing.value) return;\n  clearing.value = true;\n\n  const cleared = await clearAllEntries();\n  clearing.value = false;\n\n  toastr.success(cleared > 0 ? `已清空 ${cleared} 条 MeowDB 数据` : '当前聊天没有可清空的 MeowDB 数据');\n}\n\nfunction restoreRelationsPrompt() {\n  settings.value.relations_prompt = DEFAULT_RELATIONS_PROMPT;\n  toastr.success('已还原默认 relations 提示词');\n}\n\nwatch(\n  () => settings.value.api_active_profile_id,\n  () => {\n    ensureProfiles();\n    applyProfileToFields(activeProfile.value);\n  },\n  { immediate: true },\n);\n\nwatch(\n  () => [\n    settings.value.api_enabled,\n    settings.value.api_url,\n    settings.value.api_key,\n    settings.value.api_model,\n    settings.value.api_temperature,\n    settings.value.api_max_tokens,\n  ],\n  () => syncFieldsToActiveProfile(),\n);\n\nonMounted(() => {\n  ensureProfiles();\n  applyProfileToFields(activeProfile.value);\n});\n</script>\n","import SettingsPanel from '@/ui/settings/SettingsPanel.vue';\n\nconst TOP_DRAWER_ID = 'MeowDB_drawer';\nconst TOP_ICON_ID = 'MeowDB_drawer_icon';\nconst TOP_DUMMY_CONTENT_ID = 'MeowDB_drawer_content';\nconst MODAL_OVERLAY_ID = 'MeowDB_settings_overlay';\nconst MODAL_ROOT_ID = 'MeowDB_settings_root';\n\nlet app: ReturnType<typeof createApp> | null = null;\n\nexport function initSettingsUI() {\n  const holder = document.querySelector('#top-settings-holder') as HTMLElement | null;\n  if (!holder) return;\n\n  const drawer = ensureTopDrawer(holder);\n  const icon = drawer.querySelector(`#${TOP_ICON_ID}`) as HTMLElement | null;\n  if (!icon) return;\n\n  const overlay = ensureModalOverlay();\n  mountSettingsApp();\n  bindModalEvents(icon, overlay);\n}\n\nfunction ensureTopDrawer(holder: HTMLElement): HTMLElement {\n  let drawer = holder.querySelector(`#${TOP_DRAWER_ID}`) as HTMLElement | null;\n\n  if (!drawer) {\n    drawer = document.createElement('div');\n    drawer.id = TOP_DRAWER_ID;\n    drawer.className = 'drawer';\n    drawer.innerHTML = `\n      <div class=\"drawer-toggle\">\n        <div id=\"${TOP_ICON_ID}\" class=\"drawer-icon fa-solid fa-paw fa-fw closedIcon interactable\" title=\"MeowDB 设置\" tabindex=\"0\" role=\"button\"></div>\n      </div>\n      <div id=\"${TOP_DUMMY_CONTENT_ID}\" class=\"drawer-content closedDrawer meowdb-dummy-drawer\"></div>\n    `;\n  }\n\n  placeBeforeLastDrawer(holder, drawer);\n  return drawer;\n}\n\nfunction placeBeforeLastDrawer(holder: HTMLElement, drawer: HTMLElement) {\n  const otherDrawers = Array.from(holder.children).filter(\n    (el): el is HTMLElement => el instanceof HTMLElement && el.classList.contains('drawer') && el.id !== TOP_DRAWER_ID,\n  );\n\n  const lastDrawer = otherDrawers.at(-1);\n  if (lastDrawer) {\n    holder.insertBefore(drawer, lastDrawer);\n    return;\n  }\n\n  holder.appendChild(drawer);\n}\n\nfunction ensureModalOverlay(): HTMLElement {\n  let overlay = document.querySelector(`#${MODAL_OVERLAY_ID}`) as HTMLElement | null;\n  if (overlay) return overlay;\n\n  overlay = document.createElement('div');\n  overlay.id = MODAL_OVERLAY_ID;\n  overlay.className = 'meowdb-modal-overlay';\n  overlay.innerHTML = `\n    <div class=\"meowdb-modal\" role=\"dialog\" aria-modal=\"true\" aria-label=\"MeowDB 设置\">\n      <button type=\"button\" class=\"meowdb-modal-close interactable\" title=\"关闭\">\n        <i class=\"fa-solid fa-xmark\"></i>\n      </button>\n      <div id=\"${MODAL_ROOT_ID}\"></div>\n    </div>\n  `;\n\n  document.body.appendChild(overlay);\n  return overlay;\n}\n\nfunction bindModalEvents(icon: HTMLElement, overlay: HTMLElement) {\n  if (!icon.dataset.bound) {\n    icon.dataset.bound = 'true';\n\n    icon.addEventListener('click', event => {\n      event.preventDefault();\n      event.stopPropagation();\n      openModal(overlay, icon);\n    });\n\n    icon.addEventListener('keydown', event => {\n      if (!(event instanceof KeyboardEvent)) return;\n      if (event.key !== 'Enter' && event.key !== ' ') return;\n      event.preventDefault();\n      event.stopPropagation();\n      openModal(overlay, icon);\n    });\n  }\n\n  if (!overlay.dataset.bound) {\n    overlay.dataset.bound = 'true';\n\n    overlay.addEventListener('click', event => {\n      const target = event.target as HTMLElement | null;\n      if (!target) return;\n      if (target.classList.contains('meowdb-modal-overlay')) {\n        closeModal(overlay, icon);\n      }\n    });\n\n    const closeBtn = overlay.querySelector('.meowdb-modal-close') as HTMLElement | null;\n    closeBtn?.addEventListener('click', () => closeModal(overlay, icon));\n\n    document.addEventListener('keydown', event => {\n      if (!(event instanceof KeyboardEvent)) return;\n      if (event.key !== 'Escape') return;\n      if (!overlay.classList.contains('open')) return;\n      closeModal(overlay, icon);\n    });\n  }\n}\n\nfunction openModal(overlay: HTMLElement, icon: HTMLElement) {\n  overlay.classList.add('open');\n  icon.classList.remove('closedIcon');\n  icon.classList.add('openIcon');\n}\n\nfunction closeModal(overlay: HTMLElement, icon: HTMLElement) {\n  overlay.classList.remove('open');\n  icon.classList.remove('openIcon');\n  icon.classList.add('closedIcon');\n}\n\nfunction mountSettingsApp() {\n  const mount = document.querySelector(`#${MODAL_ROOT_ID}`) as HTMLElement | null;\n  if (!mount) return;\n  if (mount.childElementCount > 0) return;\n\n  if (!app) {\n    app = createApp(SettingsPanel);\n    app.use(createPinia());\n  }\n\n  app.mount(mount);\n}\n","import '@/global.css';\nimport '@/styles/meowdb-theme.css';\nimport { initAutoReloadOnExtensionUpdate } from '@/core/auto-reload-on-update';\nimport { initPanel } from '@/ui/panel';\nimport { initSettingsUI } from '@/ui/settings';\n\n$(() => {\n  initAutoReloadOnExtensionUpdate();\n  initSettingsUI();\n  initPanel();\n});\r\n"],"names":["normalizeExtensionName","name","trim","replace","split","filter","Boolean","at","toLowerCase","initAutoReloadOnExtensionUpdate","w","window","__meowdbAutoReloadPatchInstalled","selfExtensionName","match","url","getSelfExtensionFolder","originalFetch","fetch","bind","input","init","response","URL","location","origin","pathname","isExtensionUpdateApi","toString","target","async","tryParse","text","payload","JSON","parse","extensionName","body","Request","clone","readUpdateTarget","ok","data","json","isUpToDate","__meowdbReloadScheduled","toastrRef","toastr","info","setTimeout","reload","scheduleReload","$constructor","initializer","params","inst","def","_zod","Object","defineProperty","value","constr","_","traits","Set","enumerable","has","add","proto","prototype","keys","i","length","k","Parent","Definition","_a","this","deferred","fn","Symbol","hasInstance","$ZodAsyncError","Error","constructor","super","$ZodEncodeError","globalConfig","config","newConfig","getEnumValues","entries","numericValues","values","v","indexOf","map","jsonStringifyReplacer","cache