ull {\n  const ctx = getStContext();\n  const chat = (ctx?.chat ?? []) as any[];\n  for (let i = chat.length - 1; i >= 0; i--) {\n    const entry = chat[i]?.data?.meowDB;\n    if (entry) return entry;\n  }\n  return null;\n}\n\nexport async function saveEntry(entry: MeowDBEntry): Promise<void> {\n  const ctx = getStContext();\n  const chat = (ctx?.chat ?? []) as any[];\n  const lastMsg = chat[chat.length - 1];\n  if (!lastMsg) return;\n  if (!lastMsg.data) lastMsg.data = {};\n  lastMsg.data.meowDB = entry;\n  await saveChat();\n}\n\nexport async function clearEntries(): Promise<number> {\n  const ctx = getStContext();\n  const chat = (ctx?.chat ?? []) as any[];\n  let cleared = 0;\n\n  for (const msg of chat) {\n    if (!msg?.data) continue;\n    if (msg.data.meowDB) {\n      delete msg.data.meowDB;\n      cleared += 1;\n    }\n    if (msg.data.meowDB_history) {\n      delete msg.data.meowDB_history;\n    }\n  }\n\n  if (cleared > 0) {\n    await saveChat();\n  }\n\n  return cleared;\n}\n","import { MeowDBEntrySchema, type MeowDBEntry } from '@/type/meowdb';\n\nexport function validateEntry(entry: unknown): entry is MeowDBEntry {\n  return MeowDBEntrySchema.safeParse(entry).success;\n}\n\nexport function parseEntryObject(entry: unknown): MeowDBEntry | null {\n  const parsed = MeowDBEntrySchema.safeParse(entry);\n  return parsed.success ? parsed.data : null;\n}\n","import type { MeowDBEntry } from '@/type/meowdb';\n\nexport interface PromptPayload {\n  system: string;\n  user: string;\n}\n\nexport const DEFAULT_RELATIONS_PROMPT = [\n  'relations_json 结构要求（数组，每个角色一条）：',\n  '- name: 角色名（必须包含 <user> 对应角色）',\n  '- gender: 性别',\n  '- birthday: 生日（可用 MM-DD）',\n  '- sexExp: 性经验（对象(次数)）',\n  '- coordinate: 当前位置',\n  '- action: 当前动作',\n  '- clothing: 全套服饰总览（简写）',\n  '- clothingParts: 服饰拆解对象，键必须齐全：headwear,jewelry,facewear,upper,lower,underwearTop,underwearBottom,shoesSocks',\n  '- appearance: 外貌总览（简写）',\n  '- appearanceParts: 外貌拆解对象，键必须齐全：hairColor,eyeColor,height,bodyType',\n  '- genitalStatus: 性器官及状态',\n  '- identity: 身份',\n  '- personality: 核心人格',\n  '- bond: 与对方当前羁绊描述',\n  '- favorBase: 好感基础值（number，1位小数）',\n  '- favorDelta: 本轮增减值（number，1位小数，可正可负）',\n  '- favor: 最终值，等于 favorBase + favorDelta（number，1位小数）',\n  '- favorChange: 增减原因（本轮关键事件）',\n  '- manualEdited: object，保留已有 true 字段；没有手动改动可为空对象',\n  '- aiBaseline: object，保留已有基线值；不要覆盖已存在基线',\n  '',\n  'relation 卡片语义参考：',\n  '◈ [名称] <[性别] ⌾ [性器官及状态]>',\n  '├─ [身份] , [核心人格] , [生日] , [性经验: 对象(次数)]',\n  '├─ [坐标] , [服饰拆解] , [外貌拆解] , [实时动作]',\n  '└─ [羁绊 ⌾ 基础值+增减值=最终值，增减原因: ...]',\n  '',\n  '[好感指南]',\n  '1) 锚定前值，严禁无故跳涨；单次通常 +0.1~0.8',\n  '2) 触犯禁忌/OOC/冲突时可强制扣分（-2~-10）',\n  '3) 禁止把数值变化写成直白告白，用行为细节体现关系变化',\n  '4) 对手动字段（manualEdited=true）默认保持原值，除非剧情出现明确冲突证据',\n].join('\\n');\n\ninterface BuildPromptOptions {\n  relationsPrompt?: string;\n}\n\nexport function buildPrompt(\n  currentEntry: MeowDBEntry,\n  chatHistory: string,\n  options: BuildPromptOptions = {},\n): PromptPayload {\n  const relationsPrompt = options.relationsPrompt?.trim() || DEFAULT_RELATIONS_PROMPT;\n  const manualHints = buildManualHints(currentEntry);\n\n  const system = [\n    '你是 MeowDB 剧情数据库维护器。',\n    '根据对话历史更新剧情结构化数据。',\n    '输出必须严格为 <meow_FM><details>...</details></meow_FM>。',\n    'details 内必须包含以下行键：',\n    'serial,time,nsfw,scene_main,scene_sub,scene_stay_rounds,scene_topic,plot,relations_json,echoes_json,archived_json,enigmas_json,seeds_json',\n    'plot 必须使用 plot:\\n<<<\\n...\\n>>> 结构。',\n    '其中 *_json 字段必须是合法 JSON 数组字符串。',\n    '',\n    relationsPrompt,\n    '',\n    '不要输出任何额外解释文本。',\n  ].join('\\n');\n\n  const user = [\n    '【当前数据】',\n    JSON.stringify(currentEntry),\n    '',\n    '【手动编辑保护】',\n    manualHints,\n    '',\n    '【最近对话】',\n    chatHistory || '(空)',\n    '',\n    '【要求】',\n    '- serial 在当前基础上递增',\n    '- time 反映当前轮次时间描述',\n    '- 根据剧情更新 scene / plot / relations / echoes / enigmas / seeds',\n    '- 优先保证 relations_json 字段完整、可直接用于前端卡片展示',\n    '- 对 manualEdited=true 的字段，默认保持值不变',\n  ].join('\\n');\n\n  return { system, user };\n}\n\nfunction buildManualHints(entry: MeowDBEntry): string {\n  const lines: string[] = [];\n\n  for (const relation of entry.relations ?? []) {\n    const editedKeys = Object.keys(relation.manualEdited ?? {}).filter(key => relation.manualEdited?.[key]);\n    if (!editedKeys.length) continue;\n\n    const keyText = editedKeys.join(', ');\n    lines.push(`- ${relation.name}: 锁定字段 -> ${keyText}`);\n  }\n\n  return lines.length ? lines.join('\\n') : '无手动锁定字段。';\n}\n","import { extension_settings } from '@sillytavern/scripts/extensions';\nimport { getStContext } from '@/core/api-bridge';\nimport { getCurrentEntry, saveCurrentEntry } from '@/modules/data-manager';\nimport { callApi } from '@/modules/ai-updater/api-caller';\nimport { parseResponse } from '@/modules/ai-updater/parser';\nimport { buildPrompt } from '@/modules/ai-updater/prompt-builder';\nimport { createDefaultEntry } from '@/type/meowdb';\nimport type { Settings } from '@/type/settings';\nimport { setting_field } from '@/type/settings';\n\nexport interface ManualUpdateResult {\n  ok: boolean;\n  error?: string;\n}\n\nexport async function runManualAiUpdate(): Promise<ManualUpdateResult> {\n  const settings = readSettings();\n  const currentEntry = getCurrentEntry() ?? createDefaultEntry();\n  const chatHistory = buildChatHistory();\n  const prompt = buildPrompt(currentEntry, chatHistory, { relationsPrompt: settings.relations_prompt });\n\n  try {\n    const raw = await callApi(prompt, settings);\n    const parsed = parseResponse(raw);\n    if (!parsed) {\n      return { ok: false, error: 'AI 返回无法解析为 meow_FM。' };\n    }\n\n    const saved = await saveCurrentEntry(parsed.entry);\n    if (!saved) {\n      return { ok: false, error: '解析成功，但保存前校验失败。' };\n    }\n\n    return { ok: true };\n  } catch (error) {\n    return { ok: false, error: error instanceof Error ? error.message : String(error) };\n  }\n}\n\nfunction readSettings(): Settings {\n  return (_.get(extension_settings, setting_field) as Settings | undefined) ?? ({} as Settings);\n}\n\nfunction buildChatHistory(limit = 12): string {\n  const ctx = getStContext();\n  const chat = ((ctx?.chat ?? []) as any[]).slice(-limit);\n\n  return chat\n    .map((msg, index) => {\n      const role = msg?.is_user ? 'USER' : msg?.is_system ? 'SYSTEM' : 'CHAR';\n      const text = String(msg?.mes ?? '').trim();\n      if (!text) return null;\n      return `#${index + 1} [${role}] ${text}`;\n    })\n    .filter(Boolean)\n    .join('\\n');\n}\n\nexport * from './prompt-builder';\nexport * from './api-caller';\nexport * from './parser';\n","import type { PromptPayload } from '@/modules/ai-updater/prompt-builder';\n\nexport interface AiCallerConfig {\n  api_enabled: boolean;\n  api_url: string;\n  api_key: string;\n  api_model: string;\n  api_temperature: number;\n  api_max_tokens: number;\n}\n\nexport async function callApi(prompt: PromptPayload, config: AiCallerConfig): Promise<string> {\n  if (!config.api_enabled) {\n    throw new Error('独立 API 未启用，请先在设置中开启。');\n  }\n\n  if (!config.api_url || !config.api_model) {\n    throw new Error('请先配置 API URL 和 Model。');\n  }\n\n  const endpoint = buildChatCompletionsUrl(config.api_url);\n  const response = await fetch(endpoint, {\n    method: 'POST',\n    headers: {\n      'Content-Type': 'application/json',\n      ...(config.api_key ? { Authorization: `Bearer ${config.api_key}` } : {}),\n    },\n    body: JSON.stringify({\n      model: config.api_model,\n      temperature: config.api_temperature,\n      max_tokens: config.api_max_tokens,\n      messages: [\n        { role: 'system', content: prompt.system },\n        { role: 'user', content: prompt.user },\n      ],\n    }),\n  });\n\n  if (!response.ok) {\n    const reason = await response.text();\n    throw new Error(`API 调用失败(${response.status}): ${reason}`);\n  }\n\n  const json = (await response.json()) as {\n    choices?: Array<{ message?: { content?: string } }>;\n  };\n\n  const content = json.choices?.[0]?.message?.content?.trim();\n  if (!content) {\n    throw new Error('API 返回为空。');\n  }\n\n  return content;\n}\n\nfunction buildChatCompletionsUrl(baseUrl: string): string {\n  const normalized = baseUrl.replace(/\\/$/, '');\n  if (normalized.endsWith('/chat/completions')) return normalized;\n  return `${normalized}/chat/completions`;\n}\n","import { parseEntry as parseSerializedEntry } from '@/modules/data-manager/serializer';\nimport type { MeowDBEntry } from '@/type/meowdb';\n\nexport interface ParsedAiResponse {\n  rawBlock: string;\n  entry: MeowDBEntry;\n}\n\nexport function parseResponse(raw: string): ParsedAiResponse | null {\n  const text = raw?.trim();\n  if (!text) return null;\n\n  const block = extractFmBlock(text) ?? text;\n  const entry = parseSerializedEntry(block);\n  if (!entry) return null;\n\n  return { rawBlock: block, entry };\n}\n\nfunction extractFmBlock(text: string): string | null {\n  const match = text.match(/<meow_FM>[\\s\\S]*?<\\/meow_FM>/i);\n  return match?.[0] ?? null;\n}\n","export function validateInplace<T>(schema: z.ZodType<T>, data: unknown): T {\n  const result = parsePrettified(schema, data);\n  return _.assign(data, result) as T;\n}\n\nexport function parsePrettified<T>(schema: z.ZodType<T>, data: unknown): T {\n  const result = schema.safeParse(data);\n  if (!result.success) {\n    throw Error(z.prettifyError(result.error));\n  }\n  return result.data;\n}\n","/*!\n * pinia v3.0.4\n * (c) 2025 Eduardo San Martin Morote\n * @license MIT\n */\nimport { hasInjectionContext, inject, toRaw, watch, unref, markRaw, effectScope, ref, isRef, isReactive, getCurrentScope, onScopeDispose, getCurrentInstance, reactive, toRef, nextTick, computed, toRefs } from 'vue';\nimport { setupDevtoolsPlugin } from '@vue/devtools-api';\n\nconst IS_CLIENT = typeof window !== 'undefined';\n\n/**\n * setActivePinia must be called to handle SSR at the top of functions like\n * `fetch`, `setup`, `serverPrefetch` and others\n */\nlet activePinia;\n/**\n * Sets 